const formatNumber = (num: number | undefined) => {
  return num !== undefined ? num.toFixed(2) : '-';
};

// Custom Candlestick Shape
// We bind the Bar to [low, high] so Recharts calculates the total height range.
// We then calculate the body position relative to that range.
const CandleStickShape = (props: any) => {
  const { x, y, width, height, payload } = props;
  const { open, close, high, low } = payload;

  if (open === undefined || close === undefined || high === undefined || low === undefined) return null;

  const isUp = close > open;
  const isDown = close < open;
  // Taiwan Colors: Red for Up, Green for Down
  const color = isUp ? '#ef4444' : isDown ? '#10b981' : '#94a3b8';

  // Calculate ratio: pixels per unit of price
  // The Bar is rendered from `low` to `high`. 
  // `y` is the pixel position of `high`. `height` is the pixel height from `high` to `low`.
  const priceRange = high - low;
  const ratio = priceRange === 0 ? 0 : height / priceRange;

  const bodyMax = Math.max(open, close);
  const bodyMin = Math.min(open, close);

  // Calculate body coordinates
  const bodyTopY = y + (high - bodyMax) * ratio;
  const bodyHeight = Math.max(1, (bodyMax - bodyMin) * ratio);

  return (
    <g>
      {/* Wick (High to Low) - Drawn in the center */}
      <line 
        x1={x + width / 2} 
        y1={y} 
        x2={x + width / 2} 
        y2={y + height} 
        stroke={color} 
        strokeWidth={1} 
      />
      {/* Body (Open to Close) */}
      <rect 
        x={x} 
        y={bodyTopY} 
        width={width} 
        height={bodyHeight} 
        fill={color} 
        stroke="none"
      />
    </g>
  );
};

const CustomTooltip = ({ active, payload, label, settings }: any) => {
  if (active && payload && payload.length) {
    const d = payload[0].payload as StockDataPoint;
    const isUp = d.close > d.open;
    const colorClass = isUp ? "text-red-400" : d.close < d.open ? "text-emerald-400" : "text-slate-400";

    // Format Date
    const dateStr = d.date;

    return (
      <div className="bg-slate-900/95 border border-slate-700 p-3 rounded shadow-xl text-xs font-mono z-50">
        <p className="text-slate-400 mb-2 border-b border-slate-700 pb-1">{dateStr}</p>

        {/* Price Section */}
        <div className="grid grid-cols-2 gap-x-4 gap-y-1 mb-3">
          <span className="text-slate-500">Open:</span> <span className={colorClass}>{formatNumber(d.open)}</span>
          <span className="text-slate-500">High:</span> <span className={colorClass}>{formatNumber(d.high)}</span>
          <span className="text-slate-500">Low:</span> <span className={colorClass}>{formatNumber(d.low)}</span>
          <span className="text-slate-500">Close:</span> <span className={`font-bold ${colorClass}`}>{formatNumber(d.close)}</span>
          <span className="text-slate-500">Vol:</span> <span className="text-slate-200">{d.volume.toLocaleString()}</span>
        </div>

        {/* MAs */}
        <div className="space-y-1 border-t border-slate-700 pt-2 mb-2">
            <div className="flex justify-between gap-4"><span style={{color: '#fbbf24'}}>MA {settings.maShort}:</span> <span>{formatNumber(d.ma5)}</span></div>
            <div className="flex justify-between gap-4"><span style={{color: '#a78bfa'}}>MA {settings.maMedium}:</span> <span>{formatNumber(d.ma10)}</span></div>
            <div className="flex justify-between gap-4"><span style={{color: '#22d3ee'}}>MA {settings.maLong}:</span> <span>{formatNumber(d.ma20)}</span></div>
            <div className="flex justify-between gap-4"><span style={{color: '#94a3b8'}}>MA {settings.maSuperLong}:</span> <span>{formatNumber(d.ma60)}</span></div>
        </div>

        {/* Indicators */}
        <div className="space-y-1 border-t border-slate-700 pt-2">
           <div className="flex justify-between gap-4">
             <span className="text-orange-400">RSI ({settings.rsiPeriod}):</span> 
             <span>{formatNumber(d.rsi)}</span>
           </div>
           <div className="flex justify-between gap-4">
             <span className="text-blue-400">K/D/J:</span> 
             <span>{formatNumber(d.k)}/{formatNumber(d.d)}/{formatNumber(d.j)}</span>
           </div>
            <div className="flex justify-between gap-4">
             <span className="text-pink-400">MACD:</span> 
             <span>{formatNumber(d.macd)}</span>
           </div>
        </div>
      </div>
    );
  }
  return null;
};

