import React, { useState, useEffect } from 'react';
import Sidebar from './components/Sidebar';
import StockChart from './components/StockChart';
import AnalysisResult from './components/AnalysisResult';
import { getStockData } from './services/yahoo';
import { analyzeStockWithGemini } from './services/gemini';
import { StockDataPoint, TimeRange, StockInfo, IndicatorSettings } from './types';
import { Search, AlertCircle, Loader2, X, Wallet, DollarSign, Zap, BrainCircuit } from 'lucide-react';

const App: React.FC = () => {
  const [symbol, setSymbol] = useState<string>('2330'); // Default TSMC
  const [range, setRange] = useState<TimeRange>('6mo');
  const [data, setData] = useState<StockDataPoint[]>([]);
  const [info, setInfo] = useState<StockInfo | null>(null);
  const [loading, setLoading] = useState<boolean>(false);
  const [analyzing, setAnalyzing] = useState<boolean>(false);
  const [error, setError] = useState<string | null>(null);
  const [analysis, setAnalysis] = useState<string>('');

  // Indicator Settings State
  const [settings, setSettings] = useState<IndicatorSettings>({
    maShort: 5,
    maMedium: 10,
    maLong: 20,
    maSuperLong: 60,
    rsiPeriod: 14,
    kdjPeriod: 9,
    macdFast: 12,
    macdSlow: 26,
    macdSignal: 9
  });

  // User Position State (Mocked for now, can be expanded to UI later)
  const [userPosition, setUserPosition] = useState<{ hasHolding: boolean; costPrice?: number }>({
    hasHolding: false
  });

  // Fetch Data
  useEffect(() => {
    const fetchData = async () => {
      setLoading(true);
      setError(null);
      try {
        // Pass settings to getStockData to calculate indicators dynamically
        const result = await getStockData(symbol, range, settings);
        setData(result.data);
        setInfo(result.info);
        // Reset analysis when data changes
        setAnalysis(''); 
      } catch (err: any) {
        setError(err.message || 'Failed to fetch data');
        setData([]);
        setInfo(null);
      } finally {
        setLoading(false);
      }
    };

    const debounce = setTimeout(fetchData, 800); // Debounce typing
    return () => clearTimeout(debounce);
  }, [symbol, range, settings]); // Re-fetch when settings change

  // AI Analysis Handler
  const handleAnalyze = async (mode: 'fast' | 'thinking') => {
    if (data.length === 0) return;

    setAnalyzing(true);
    setAnalysis(''); // Clear previous
    try {
        const result = await analyzeStockWithGemini(info?.symbol || symbol, data, userPosition, mode);
        setAnalysis(result);
    } catch (e: any) {
        setAnalysis(`Error: ${e.message}`);
    } finally {
        setAnalyzing(false);
    }
  };

  // User Position Handlers (Simple Toggle for Demo)
  const toggleHolding = () => {
      setUserPosition(prev => ({
          ...prev,
          hasHolding: !prev.hasHolding,
          costPrice: !prev.hasHolding ? data[data.length - 1]?.close : undefined
      }));
  };

  return (
    <div className="flex h-screen bg-slate-950 text-slate-200 overflow-hidden font-sans selection:bg-blue-500/30">
      {/* Sidebar */}
      <Sidebar 
        range={range} 
        setRange={setRange} 
        settings={settings}
        setSettings={setSettings}
      />

      {/* Main Content */}
      <div className="flex-1 flex flex-col h-full overflow-hidden relative">

        {/* Header / Search Bar */}
        <div className="h-16 border-b border-slate-800 flex items-center px-6 gap-4 bg-slate-900/50 backdrop-blur-sm shrink-0 z-20">
            <div className="relative group">
                <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-500 group-focus-within:text-blue-400 transition-colors" size={18} />
                <input 
                    type="text" 
                    value={symbol}
                    onChange={(e) => setSymbol(e.target.value.toUpperCase())}
                    placeholder="Enter Stock Symbol (e.g. 2330, AAPL)"
                    className="bg-slate-800/50 border border-slate-700 text-slate-200 pl-10 pr-4 py-2 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500/50 focus:border-blue-500 w-64 transition-all placeholder:text-slate-600 font-mono uppercase"
                />
            </div>

            {info && (
                <div className="flex items-center gap-3 animate-in fade-in slide-in-from-left-4 duration-500">
                    <div className="flex flex-col">
                        <h1 className="text-lg font-bold text-white leading-tight">{info.name}</h1>
                        <div className="flex items-center gap-2 text-xs text-slate-400">
                            <span className="bg-slate-800 px-1.5 py-0.5 rounded text-blue-300 font-mono">{info.symbol}</span>
                            <span>{info.currency} • {info.exchangeTimezoneName}</span>
                        </div>
                    </div>
                </div>
            )}

            <div className="flex-1" />

            {/* Mock User Position Toggle */}
            <button 
                onClick={toggleHolding}
                className={`flex items-center gap-2 px-3 py-1.5 rounded-lg text-xs font-medium border transition-all ${
                    userPosition.hasHolding 
                    ? 'bg-emerald-500/10 border-emerald-500/30 text-emerald-400' 
                    : 'bg-slate-800 border-slate-700 text-slate-500 hover:text-slate-300'
                }`}
            >
                <Wallet size={14} />
                {userPosition.hasHolding ? `Holding @ ${userPosition.costPrice?.toFixed(2)}` : 'Simulate Holding'}
            </button>
        </div>

        {/* Scrollable Content Area */}
        <div className="flex-1 overflow-y-auto p-6 scroll-smooth">
            <div className="max-w-7xl mx-auto space-y-6 pb-20">

                {/* Error State */}
                {error && (
                    <div className="bg-red-500/10 border border-red-500/20 text-red-400 p-4 rounded-xl flex items-center gap-3">
                        <AlertCircle size={20} />
                        <p>{error}</p>
                    </div>
                )}

                {/* Loading State */}
                {loading && (
                    <div className="flex flex-col items-center justify-center h-[400px] text-slate-500 gap-3">
                        <Loader2 className="animate-spin text-blue-500" size={32} />
                        <p className="animate-pulse">Fetching market data...</p>
                    </div>
                )}

                {/* Data Content */}
                {!loading && !error && data.length > 0 && (
                    <>
                         {/* Chart Section */}
                        <StockChart data={data} settings={settings} />

                        {/* Analysis Controls */}
                        <div className="flex flex-col sm:flex-row gap-4 items-center justify-between bg-slate-800/50 p-6 rounded-xl border border-slate-700/50 backdrop-blur mt-8">
                            <div>
                                <h3 className="text-lg font-semibold text-white mb-1 flex items-center gap-2">
                                    <BrainCircuit className="text-purple-400" size={20} />
                                    AI Strategy Generator
                                </h3>
                                <p className="text-slate-400 text-sm">Generate professional entry/exit plans based on current technicals.</p>
                            </div>

                            <div className="flex gap-3">
                                <button
                                    onClick={() => handleAnalyze('fast')}
                                    disabled={analyzing}
                                    className="flex items-center gap-2 px-5 py-2.5 bg-slate-700 hover:bg-slate-600 text-white rounded-lg font-medium transition-all disabled:opacity-50 disabled:cursor-not-allowed border border-slate-600 hover:border-slate-500 shadow-lg shadow-black/20"
                                >
                                    {analyzing ? <Loader2 className="animate-spin" size={18} /> : <Zap size={18} className="text-yellow-400" />}
                                    Fast Check
                                </button>
                                <button
                                    onClick={() => handleAnalyze('thinking')}
                                    disabled={analyzing}
                                    className="flex items-center gap-2 px-5 py-2.5 bg-gradient-to-r from-blue-600 to-indigo-600 hover:from-blue-500 hover:to-indigo-500 text-white rounded-lg font-medium transition-all shadow-lg shadow-blue-500/20 disabled:opacity-50 disabled:cursor-not-allowed transform active:scale-95"
                                >
                                    {analyzing ? <Loader2 className="animate-spin" size={18} /> : <BrainCircuit size={18} />}
                                    Deep Analysis
                                </button>
                            </div>
                        </div>

                        {/* Analysis Result */}
                        <div id="analysis-section" className="scroll-mt-6">
                            {(analyzing || analysis) && (
                                <AnalysisResult content={analysis} loading={analyzing} />
                            )}
                        </div>
                    </>
                )}
            </div>
        </div>
      </div>
    </div>
  );
};

export default App;

