const fetchFinMindStockInfo = async (stockId: string) => {
    const cleanId = stockId.replace('.TW', '').replace('.TWO', '');
    const url = `${FINMIND_BASE}?dataset=TaiwanStockInfo&data_id=${cleanId}`;

    try {
        const res = await fetch(url);
        const json = await res.json();
        if (json.msg === 'success' && Array.isArray(json.data) && json.data.length > 0) {
            return json.data[0].stock_name; 
        }
        return null;
    } catch (e) {
        console.warn("Failed to fetch stock info from FinMind", e);
        return null;
    }
};

const fetchRawData = async (symbol: string, interval: TimeInterval) => {
  // Logic to determine appropriate range based on interval
  // Yahoo Limits:
  // 15m -> Max ~60d
  // 30m/60m -> Max ~730d (2y)
  // 1d/1wk/1mo -> Max Unlimited (we use 5y or 10y for good MA calc)

  let range = '5y';

  if (interval === '15m') range = '60d';
  else if (interval === '30m' || interval === '60m') range = '1y'; 

  const cleanSymbol = symbol.trim().toUpperCase();

  const looksLikeTaiwanStock = /[0-9]/.test(cleanSymbol);

  if (looksLikeTaiwanStock) {
      const target = cleanSymbol.replace('.TW', '').replace('.TWO', '');
      try {
          return await queryYahoo(`${target}.TW`, interval, range);
      } catch (e) {
          console.log(`Failed to fetch ${target}.TW, trying .TWO`);
          return await queryYahoo(`${target}.TWO`, interval, range);
      }
  } else {
      try {
          return await queryYahoo(cleanSymbol, interval, range);
      } catch (e) {
          console.log(`Failed to fetch ${cleanSymbol}, trying fallback suffixes`);
          try {
             return await queryYahoo(`${cleanSymbol}.TW`, interval, range);
          } catch {
             return await queryYahoo(`${cleanSymbol}.TWO`, interval, range);
          }
      }
  }
};

const queryYahoo = async (symbol: string, interval: string, range: string): Promise<YahooChartResponse> => {
    // interval can be: 1m, 2m, 5m, 15m, 30m, 60m, 90m, 1h, 1d, 5d, 1wk, 1mo, 3mo
    const url = `${CORS_PROXY}${encodeURIComponent(`${YAHOO_BASE}${symbol}?interval=${interval}&range=${range}&lang=zh-Hant-TW&region=TW`)}`;
    const res = await fetch(url);
    if (!res.ok) throw new Error(`Fetch error: ${res.statusText}`);
    const json = await res.json();
    if (json.chart.error) throw new Error(JSON.stringify(json.chart.error));
    if (!json.chart.result || json.chart.result.length === 0) throw new Error('No data found');
    return json as YahooChartResponse;
};

export const getStockData = async (symbol: string, interval: TimeInterval = '1d', settings: IndicatorSettings): Promise<{info: StockInfo, data: StockDataPoint[]}> => {
  // 1. Fetch history from Yahoo based on interval
  const response = await fetchRawData(symbol, interval);
  const result = response.chart.result![0];
  const meta = result.meta;
  const timestamps = result.timestamp;
  const quote = result.indicators.quote[0];

  if (!timestamps || !quote || !quote.close) {
      throw new Error("Invalid data structure received from API");
  }

  const closes = quote.close;
  const opens = quote.open;
  const highs = quote.high;
  const lows = quote.low;
  const volumes = quote.volume; 

  const isTaiwanStock = meta.symbol.endsWith('.TW') || meta.symbol.endsWith('.TWO');
  const isIntraday = interval.includes('m'); // 15m, 30m, 60m

  // 2. Fetch FinMind Data ONLY if it's a Taiwan stock AND Daily timeframe
  // FinMind API generally provides daily closing data. For intraday, we rely purely on Yahoo.
  const chipMap = new Map<string, { foreign: number, trust: number }>();
  const volumeMap = new Map<string, number>();
  let taiwanStockName: string | null = null;

  if (isTaiwanStock) {
       // Name fetching works regardless of timeframe
      const nameData = await fetchFinMindStockInfo(meta.symbol);
      if (nameData) taiwanStockName = nameData;

      // Chip/Volume correction only for Daily data
      if (!isIntraday) {
        let fetchStartDate = new Date();
        fetchStartDate.setFullYear(fetchStartDate.getFullYear() - 5); 
        const fetchStartDateStr = fetchStartDate.toISOString().split('T')[0];

        const [institutionalData, finMindPriceData] = await Promise.all([
            fetchInstitutionalData(meta.symbol, fetchStartDateStr),
            fetchFinMindPriceVolume(meta.symbol, fetchStartDateStr)
        ]);

        institutionalData.forEach((item: any) => {
            const date = item.date; 
            const net = (item.buy || 0) - (item.sell || 0);
            if (!chipMap.has(date)) chipMap.set(date, { foreign: 0, trust: 0 });
            const record = chipMap.get(date)!;
            if (item.name === 'Foreign_Investor') record.foreign += net;
            else if (item.name === 'Investment_Trust') record.trust += net;
        });

        finMindPriceData.forEach((item: any) => {
            volumeMap.set(item.date, item.Trading_Volume); 
        });
      }
  }

  // 3. Process and Merge Data
  const cleanData: any[] = [];
  timestamps.forEach((ts, i) => {
      if (closes[i] !== null && opens[i] !== null && highs[i] !== null && lows[i] !== null && closes[i] > 0) {
          // Date String: For intraday, we need time; for daily, just date
          const dateObj = new Date(ts * 1000);

          let dateStr;
          if (isIntraday) {
              // MM-DD HH:mm
              const month = (dateObj.getMonth() + 1).toString().padStart(2, '0');
              const day = dateObj.getDate().toString().padStart(2, '0');
              const hours = dateObj.getHours().toString().padStart(2, '0');
              const mins = dateObj.getMinutes().toString().padStart(2, '0');
              dateStr = `${month}-${day} ${hours}:${mins}`;
          } else {
               dateStr = dateObj.toISOString().split('T')[0];
          }

          let finalVolume = 0;
          if (isTaiwanStock && !isIntraday && volumeMap.has(dateStr)) {
              finalVolume = volumeMap.get(dateStr)!;
          } else {
              finalVolume = (volumes && volumes[i]) ? volumes[i] : 0;
          }

          cleanData.push({
              date: dateStr,
              timestamp: ts,
              open: opens[i],
              high: highs[i],
              low: lows[i],
              close: closes[i],
              volume: finalVolume 
          });
      }
  });

  // 4. Calculate Indicators using custom settings
  const closeValues = cleanData.map(d => d.close);
  const highValues = cleanData.map(d => d.high);
  const lowValues = cleanData.map(d => d.low);

  const ma5 = calculateSMA(closeValues, settings.maShort);
  const ma10 = calculateSMA(closeValues, settings.maMedium);
  const ma20 = calculateSMA(closeValues, settings.maLong);
  const ma60 = calculateSMA(closeValues, settings.maSuperLong);

  const rsi = calculateRSI(closeValues, settings.rsiPeriod);
  const { macdLine, signalLine, histogram } = calculateMACD(closeValues, settings.macdFast, settings.macdSlow, settings.macdSignal);
  const { K, D, J } = calculateKDJ(highValues, lowValues, closeValues, settings.kdjPeriod);

  const fullProcessedData: StockDataPoint[] = cleanData.map((d, i) => {
      const getDir = (current: number | undefined, prev: number | undefined) => {
          if (current === undefined || prev === undefined) return 'flat';
          return current > prev ? 'up' : current < prev ? 'down' : 'flat';
      };

      const chips = chipMap.get(d.date) || { foreign: 0, trust: 0 };

      return {
          ...d,
          ma5: ma5[i] || undefined,
          ma10: ma10[i] || undefined,
          ma20: ma20[i] || undefined,
          ma60: ma60[i] || undefined,
          ma5Dir: i > 0 ? getDir(ma5[i], ma5[i-1]) : 'flat',
          ma10Dir: i > 0 ? getDir(ma10[i], ma10[i-1]) : 'flat',
          ma20Dir: i > 0 ? getDir(ma20[i], ma20[i-1]) : 'flat',
          ma60Dir: i > 0 ? getDir(ma60[i], ma60[i-1]) : 'flat',

          rsi: rsi[i] || undefined,
          macd: macdLine[i] || undefined,
          macdSignal: signalLine[i] || undefined,
          macdHist: histogram[i] || undefined,
          k: K[i],
          d: D[i],
          j: J[i],

          foreignBuySell: chips.foreign, 
          investmentTrustBuySell: chips.trust
      };
  });

  // Since we are fetching tailored ranges (e.g. 60d for 15m), we typically return the whole dataset 
  // or a reasonable slice. For consistency, let's just return what we fetched.
  // The UI Zoom will handle the visual "range"

  let displayName = meta.longName || meta.shortName || meta.symbol;
  if (isTaiwanStock && taiwanStockName) {
      displayName = taiwanStockName;
  }

  return {
      info: {
          symbol: meta.symbol,
          name: displayName,
          currency: meta.currency,
          exchangeTimezoneName: meta.exchangeTimezoneName
      },
      data: fullProcessedData
  };
};

import React, { useState, useEffect } from 'react';
import Sidebar from './components/Sidebar';
import StockChart from './components/StockChart';
import AnalysisResult from './components/AnalysisResult';
import { getStockData } from './services/yahoo';
import { analyzeStockWithGemini } from './services/gemini';
import { StockDataPoint, TimeInterval, StockInfo, IndicatorSettings } from './types';
import { Search, AlertCircle, Loader2, X, Wallet, DollarSign, Zap, BrainCircuit } from 'lucide-react';

const App: React.FC = () => {
  const [symbol, setSymbol] = useState<string>('2330'); // Default TSMC
  const [interval, setInterval] = useState<TimeInterval>('1d'); // Default Daily
  const [data, setData] = useState<StockDataPoint[]>([]);
  const [info, setInfo] = useState<StockInfo | null>(null);
  const [loading, setLoading] = useState<boolean>(false);
  const [analyzing, setAnalyzing] = useState<boolean>(false);
  const [error, setError] = useState<string | null>(null);
  const [analysis, setAnalysis] = useState<string>('');

  // Indicator Settings State
  const [settings, setSettings] = useState<IndicatorSettings>({
    maShort: 5,
    maMedium: 10,
    maLong: 20,
    maSuperLong: 60,
    rsiPeriod: 14,
    kdjPeriod: 9,
    macdFast: 12,
    macdSlow: 26,
    macdSignal: 9,
    // Visibility Toggles
    visible: {
        maShort: true,
        maMedium: true,
        maLong: true,
        maSuperLong: true,
        rsi: true,
        k: true,
        d: true,
        j: true,
        macd: true
    }
  });

  // User Position State
  const [userPosition, setUserPosition] = useState<{ hasHolding: boolean; costPrice?: number }>({
    hasHolding: false
  });

  // Modal State
  const [showAnalysisModal, setShowAnalysisModal] = useState(false);
  const [modalHasHolding, setModalHasHolding] = useState<boolean | null>(null);
  const [modalCostPrice, setModalCostPrice] = useState<string>('');
  const [analysisMode, setAnalysisMode] = useState<'fast' | 'thinking'>('fast');

  // Fetch Data
  useEffect(() => {
    const fetchData = async () => {
      setLoading(true);
      setError(null);
      try {
        const result = await getStockData(symbol, interval, settings);
        setData(result.data);
        setInfo(result.info);
        setAnalysis(''); 
      } catch (err: any) {
        setError(err.message || 'Failed to fetch data');
        setData([]);
        setInfo(null);
      } finally {
        setLoading(false);
      }
    };

    const debounce = setTimeout(fetchData, 800); 
    return () => clearTimeout(debounce);
  }, [symbol, interval, settings.maShort, settings.maMedium, settings.maLong, settings.maSuperLong]); // Re-fetch only if parameters affecting calculation change. Visibility changes shouldn't trigger re-fetch.

  // AI Analysis Handler
  const handleAnalyze = async (mode: 'fast' | 'thinking') => {
    if (data.length === 0) return;

    setAnalyzing(true);
    setAnalysis(''); 
    try {
        const result = await analyzeStockWithGemini(info?.symbol || symbol, data, userPosition, mode);
        setAnalysis(result);
    } catch (e: any) {
        setAnalysis(`Error: ${e.message}`);
    } finally {
        setAnalyzing(false);
    }
  };

  const handleOpenAnalysisModal = () => {
    if (data.length === 0) return;
    setModalHasHolding(null);
    setModalCostPrice('');
    setAnalysisMode('fast');
    setShowAnalysisModal(true);
  }

  const handleRunAnalysis = async () => {
    setShowAnalysisModal(false);

    // Update main user position state based on modal
    const pos = {
        hasHolding: modalHasHolding === true,
        costPrice: modalHasHolding && modalCostPrice ? parseFloat(modalCostPrice) : undefined
    };
    setUserPosition(pos);

    setAnalyzing(true);
    try {
      const result = await analyzeStockWithGemini(info?.symbol || symbol, data, pos, analysisMode);
      setAnalysis(result);
      setTimeout(() => {
          const element = document.getElementById('analysis-section');
          if (element) element.scrollIntoView({ behavior: 'smooth' });
      }, 100);
    } catch (e: any) {
       if(e.message.includes("API Key is missing")) {
            setAnalysis("### System Error \n\n **API Key Missing.** \nPlease set `REACT_APP_GEMINI_API_KEY` in your environment.");
       } else {
            setAnalysis(`Error: ${e.message}`);
       }
    } finally {
        setAnalyzing(false);
    }
  };

  return (
    <div className="flex h-screen bg-slate-950 text-slate-200 overflow-hidden font-sans selection:bg-blue-500/30">

       {/* Analysis Modal */}
       {showAnalysisModal && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/70 backdrop-blur-sm p-4">
            <div className="bg-slate-800 border border-slate-700 rounded-2xl shadow-2xl w-full max-w-md overflow-hidden animate-in fade-in zoom-in duration-200">
                <div className="flex justify-between items-center p-4 border-b border-slate-700 bg-slate-800/50">
                    <h3 className="text-lg font-bold text-white flex items-center gap-2">
                        <BrainCircuit className="text-blue-400" size={20}/> AI 分析設定
                    </h3>
                    <button onClick={() => setShowAnalysisModal(false)} className="text-slate-400 hover:text-white transition-colors">
                        <X size={20} />
                    </button>
                </div>

                <div className="p-6 space-y-6">
                    <div className="space-y-3">
                        <p className="text-slate-300 font-medium text-sm">選擇分析模式</p>
                        <div className="grid grid-cols-2 gap-3">
                            <button
                                onClick={() => setAnalysisMode('fast')}
                                className={`flex items-center justify-center gap-2 p-3 rounded-xl border transition-all ${
                                    analysisMode === 'fast'
                                    ? 'bg-blue-600/20 border-blue-500 text-blue-400 font-bold shadow-[0_0_15px_rgba(59,130,246,0.2)]'
                                    : 'bg-slate-900 border-slate-700 text-slate-400 hover:border-slate-500 hover:bg-slate-800'
                                }`}
                            >
                                <Zap size={18} /> 快捷 (Flash)
                            </button>
                            <button
                                onClick={() => setAnalysisMode('thinking')}
                                className={`flex items-center justify-center gap-2 p-3 rounded-xl border transition-all ${
                                    analysisMode === 'thinking'
                                    ? 'bg-purple-600/20 border-purple-500 text-purple-400 font-bold shadow-[0_0_15px_rgba(168,85,247,0.2)]'
                                    : 'bg-slate-900 border-slate-700 text-slate-400 hover:border-slate-500 hover:bg-slate-800'
                                }`}
                            >
                                <BrainCircuit size={18} /> 思考 (Pro)
                            </button>
                        </div>
                    </div>

                    <div className="border-t border-slate-700/50" />

                    <div className="space-y-3">
                        <p className="text-slate-300 font-medium text-sm">您目前是否持有 <span className="text-white font-bold">{info?.symbol}</span> ？</p>
                        <div className="grid grid-cols-2 gap-3">
                            <button 
                                onClick={() => setModalHasHolding(true)}
                                className={`flex items-center justify-center gap-2 p-3 rounded-xl border transition-all ${
                                    modalHasHolding === true 
                                    ? 'bg-blue-600/20 border-blue-500 text-blue-400 font-bold shadow-[0_0_15px_rgba(59,130,246,0.2)]' 
                                    : 'bg-slate-900 border-slate-700 text-slate-400 hover:border-slate-500 hover:bg-slate-800'
                                }`}
                            >
                                <Wallet size={18} /> 持有中
                            </button>
                            <button 
                                onClick={() => setModalHasHolding(false)}
                                className={`flex items-center justify-center gap-2 p-3 rounded-xl border transition-all ${
                                    modalHasHolding === false 
                                    ? 'bg-emerald-600/20 border-emerald-500 text-emerald-400 font-bold shadow-[0_0_15px_rgba(16,185,129,0.2)]' 
                                    : 'bg-slate-900 border-slate-700 text-slate-400 hover:border-slate-500 hover:bg-slate-800'
                                }`}
                            >
                                <Search size={18} /> 空手
                            </button>
                        </div>
                    </div>

                    {modalHasHolding === true && (
                        <div className="space-y-2 animate-in fade-in slide-in-from-top-2 duration-300">
                            <label className="text-slate-300 font-medium text-sm block">平均成本 (元)</label>
                            <div className="relative">
                                <DollarSign className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-500" size={16} />
                                <input 
                                    type="number" 
                                    value={modalCostPrice}
                                    onChange={(e) => setModalCostPrice(e.target.value)}
                                    placeholder="500.5"
                                    className="w-full bg-slate-900 border border-slate-700 text-white pl-10 pr-4 py-3 rounded-xl focus:outline-none focus:ring-2 focus:ring-blue-500/50 focus:border-blue-500 transition-all placeholder:text-slate-600"
                                />
                            </div>
                        </div>
                    )}

                    <button 
                        onClick={handleRunAnalysis}
                        disabled={modalHasHolding === null || (modalHasHolding === true && !modalCostPrice)}
                        className="w-full bg-gradient-to-r from-indigo-600 to-purple-600 hover:from-indigo-500 hover:to-purple-500 text-white py-4 rounded-xl font-bold text-lg shadow-lg disabled:opacity-50 disabled:cursor-not-allowed transition-all mt-4 flex items-center justify-center gap-2"
                    >
                        <BrainCircuit className="w-6 h-6" /> 開始分析
                    </button>
                </div>
            </div>
        </div>
      )}

      {/* Sidebar */}
      <Sidebar 
        interval={interval} 
        setInterval={setInterval} 
        settings={settings}
        setSettings={setSettings}
      />

      {/* Main Content */}
      <div className="flex-1 flex flex-col h-full overflow-hidden relative">

        {/* Header / Search Bar */}
        <div className="h-16 border-b border-slate-800 flex items-center px-6 gap-4 bg-slate-900/50 backdrop-blur-sm shrink-0 z-20">
            <div className="relative group">
                <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-500 group-focus-within:text-blue-400 transition-colors" size={18} />
                <input 
                    type="text" 
                    value={symbol}
                    onChange={(e) => setSymbol(e.target.value.toUpperCase())}
                    placeholder="輸入代號 (如 2330)"
                    className="bg-slate-800/50 border border-slate-700 text-slate-200 pl-10 pr-4 py-2 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500/50 focus:border-blue-500 w-48 transition-all placeholder:text-slate-600 font-mono uppercase"
                />
            </div>

            {info && (
                <div className="flex items-center gap-3 animate-in fade-in slide-in-from-left-4 duration-500">
                    <div className="flex flex-col">
                        <h1 className="text-lg font-bold text-white leading-tight">{info.name}</h1>
                        <div className="flex items-center gap-2 text-xs text-slate-400">
                            <span className="bg-slate-800 px-1.5 py-0.5 rounded text-blue-300 font-mono">{info.symbol}</span>
                            <span>{info.currency}</span>
                        </div>
                    </div>
                </div>
            )}

            <div className="flex-1" />

            <button
                onClick={handleOpenAnalysisModal}
                disabled={analyzing || loading || data.length === 0}
                className="flex items-center gap-2 px-4 py-2 bg-indigo-600 hover:bg-indigo-500 text-white rounded-lg font-medium transition-all shadow-lg shadow-indigo-500/20 disabled:opacity-50"
            >
                {analyzing ? <Loader2 className="animate-spin" size={16} /> : <BrainCircuit size={16} />}
                <span>AI 診斷</span>
            </button>
        </div>

        {/* Scrollable Content Area */}
        <div className="flex-1 overflow-y-auto p-4 scroll-smooth">
            <div className="max-w-full h-full flex flex-col">

                {/* Error State */}
                {error && (
                    <div className="bg-red-500/10 border border-red-500/20 text-red-400 p-4 rounded-xl flex items-center gap-3 mb-4">
                        <AlertCircle size={20} />
                        <p>{error}</p>
                    </div>
                )}

                {/* Loading State */}
                {loading && (
                    <div className="flex flex-col items-center justify-center h-[400px] text-slate-500 gap-3">
                        <Loader2 className="animate-spin text-blue-500" size={32} />
                        <p className="animate-pulse">讀取市場數據中...</p>
                    </div>
                )}

                {/* Data Content */}
                {!loading && !error && data.length > 0 && (
                    <div className="flex flex-col gap-4">
                         {/* Chart Section */}
                        <StockChart data={data} settings={settings} />

                        {/* Analysis Result */}
                        <div id="analysis-section" className="scroll-mt-6">
                            {(analyzing || analysis) && (
                                <AnalysisResult content={analysis} loading={analyzing} />
                            )}
                        </div>
                    </div>
                )}
            </div>
        </div>
      </div>
    </div>
  );
};

