const StockChart: React.FC<StockChartProps> = ({ data, settings }) => {
  // Zoom State (Slice Indices)
  const [zoomState, setZoomState] = useState<{ start: number, end: number }>({ start: 0, end: data.length });

  // Reset zoom when data changes completely (new symbol/interval)
  useEffect(() => {
      setZoomState({ start: Math.max(0, data.length - 100), end: data.length });
  }, [data]);

  // Handle Wheel Zoom
  const handleWheel = (e: React.WheelEvent) => {
      e.preventDefault();

      const { start, end } = zoomState;
      const currentLength = end - start;
      const zoomSpeed = Math.max(1, Math.floor(currentLength * 0.1)); // 10% zoom speed

      let newStart = start;
      let newEnd = end;

      if (e.deltaY < 0) {
          // Zoom In (Shrink window)
          newStart = Math.min(start + zoomSpeed, end - 10); // Keep at least 10 bars
          newEnd = Math.max(end - zoomSpeed, start + 10);
      } else {
          // Zoom Out (Expand window)
          newStart = Math.max(0, start - zoomSpeed);
          newEnd = Math.min(data.length, end + zoomSpeed);
      }

      setZoomState({ start: newStart, end: newEnd });
  };

  // Prepare Sliced Data
  const chartData = useMemo(() => {
      const sliced = data.slice(zoomState.start, zoomState.end);
      return sliced.map(d => ({
        ...d,
        priceRange: [d.low, d.high],
        volColor: d.close > d.open ? '#ef4444' : d.close < d.open ? '#10b981' : '#94a3b8'
