            {settings.visible.maShort && <Line type="monotone" dataKey="ma5" name={`MA ${settings.maShort}`} stroke="#fbbf24" strokeWidth={1.5} dot={false} activeDot={{ r: 4 }} isAnimationActive={false}/>}
