const fetchRawData = async (symbol: string, interval: TimeInterval) => {
  // Use extended ranges to ensure MA calculations (especially MA60) have enough head-room
  let range = '10y';

  switch (interval) {
      case '15m':
          range = '60d'; // Max allowable for 15m
          break;
      case '60m':
          range = '730d'; // Max allowable for 1h (2 years)
          break;
      case '1d':
          range = '10y'; 
          break;
      case '1wk':
          range = '10y';
          break;
      case '1mo':
          range = 'max'; // Use MAX to get full history for monthly MA
          break;
      default:
          range = '5y';
  }

  const cleanSymbol = symbol.trim().toUpperCase();
  const looksLikeTaiwanStock = /[0-9]/.test(cleanSymbol);

  if (looksLikeTaiwanStock) {
      const target = cleanSymbol.replace('.TW', '').replace('.TWO', '');
      try {
          return await queryYahoo(`${target}.TW`, interval, range);
      } catch (e) {
          console.log(`Failed to fetch ${target}.TW, trying .TWO`);
          return await queryYahoo(`${target}.TWO`, interval, range);
      }
  } else {
      try {
          return await queryYahoo(cleanSymbol, interval, range);
      } catch (e) {
          try {
             return await queryYahoo(`${cleanSymbol}.TW`, interval, range);
          } catch {
             return await queryYahoo(`${cleanSymbol}.TWO`, interval, range);
          }
      }
  }
};

const queryYahoo = async (symbol: string, interval: string, range: string): Promise<YahooChartResponse> => {
    // We add includeAdjustedClose=true explicitly, although it's often default
    const url = `${CORS_PROXY}${encodeURIComponent(`${YAHOO_BASE}${symbol}?interval=${interval}&range=${range}&includeAdjustedClose=true&lang=zh-Hant-TW&region=TW`)}`;
    const res = await fetch(url);
    if (!res.ok) throw new Error(`Fetch error: ${res.statusText}`);
    const json = await res.json();
    if (json.chart.error) throw new Error(JSON.stringify(json.chart.error));
    if (!json.chart.result || json.chart.result.length === 0) throw new Error('No data found');
    return json as YahooChartResponse;
};

export const getStockData = async (symbol: string, interval: TimeInterval = '1d'): Promise<{info: StockInfo, data: StockDataPoint[]}> => {
  // 1. Fetch from Yahoo
  const response = await fetchRawData(symbol, interval);
  const result = response.chart.result![0];
  const meta = result.meta;
  const timestamps = result.timestamp;
  const quote = result.indicators.quote[0];
  const adjClose = result.indicators.adjclose?.[0]?.adjclose; // Extract Adjusted Close

  if (!timestamps || !quote || !quote.close) {
      throw new Error("Invalid data structure received from API");
  }

  const closes = quote.close;
  const opens = quote.open;
  const highs = quote.high;
  const lows = quote.low;
  const volumes = quote.volume; 

  const isTaiwanStock = meta.symbol.endsWith('.TW') || meta.symbol.endsWith('.TWO');
  const isIntraday = interval.includes('m'); // 15m, 60m

  // Decide whether to use Adjusted Close for Indicators
  // Usually, Intraday does not use Adj Close, but Daily/Weekly/Monthly does.
  const useAdjClose = !isIntraday && adjClose && adjClose.length === closes.length;

  // 2. Fetch FinMind Data (Only for Daily/Taiwan)
  const chipMap = new Map<string, { foreign: number, trust: number }>();
  const volumeMap = new Map<string, number>();
  let taiwanStockName: string | null = null;

  if (isTaiwanStock) {
      const fetchedName = await fetchFinMindStockInfo(meta.symbol);
      if (fetchedName) taiwanStockName = fetchedName;

      if (interval === '1d') {
        let fetchStartDate = new Date();
        fetchStartDate.setFullYear(fetchStartDate.getFullYear() - 5); 
        const fetchStartDateStr = fetchStartDate.toISOString().split('T')[0];

        const [institutionalData, finMindPriceData] = await Promise.all([
            fetchInstitutionalData(meta.symbol, fetchStartDateStr),
            fetchFinMindPriceVolume(meta.symbol, fetchStartDateStr),
        ]);

        institutionalData.forEach((item: any) => {
            const date = item.date; 
            const net = (item.buy || 0) - (item.sell || 0);
            if (!chipMap.has(date)) chipMap.set(date, { foreign: 0, trust: 0 });
            const record = chipMap.get(date)!;
            if (item.name === 'Foreign_Investor') record.foreign += net;
            else if (item.name === 'Investment_Trust') record.trust += net;
        });

        finMindPriceData.forEach((item: any) => {
            volumeMap.set(item.date, item.Trading_Volume); 
        });
      }
  }

  // 3. Process Data
  const cleanData: any[] = [];
  // Arrays for Indicator Calculation (may use Adj Close)
  const calcCloses: number[] = [];
  const calcHighs: number[] = [];
  const calcLows: number[] = [];

  timestamps.forEach((ts, i) => {
      if (closes[i] !== null && opens[i] !== null && highs[i] !== null && lows[i] !== null && closes[i] > 0) {
          const dateObj = new Date(ts * 1000);

          let dateStr;
          if (isIntraday) {
              const month = (dateObj.getMonth() + 1).toString().padStart(2, '0');
              const day = dateObj.getDate().toString().padStart(2, '0');
              const hour = dateObj.getHours().toString().padStart(2, '0');
              const min = dateObj.getMinutes().toString().padStart(2, '0');
              dateStr = `${month}-${day} ${hour}:${min}`;
          } else {
              dateStr = dateObj.toISOString().split('T')[0];
          }

          let finalVolume = 0;
          if (isTaiwanStock && !isIntraday && volumeMap.has(dateStr)) {
              finalVolume = volumeMap.get(dateStr)!;
          } else {
              finalVolume = (volumes && volumes[i]) ? volumes[i] : 0;
          }

          // Use Adjusted Close for calculation if applicable, otherwise normal Close
          // Note: We still DISPLAY normal OHLC in the chart candles, but use Adj Close for MA/RSI lines
          const priceForCalc = (useAdjClose && adjClose![i]) ? adjClose![i] : closes[i];

          cleanData.push({
              date: dateStr,
              timestamp: ts,
              open: opens[i],
              high: highs[i],
              low: lows[i],
              close: closes[i],
              volume: finalVolume 
          });

          calcCloses.push(priceForCalc);
          // For KDJ, High/Low should technically be adjusted too if we use Adj Close, 
          // but Yahoo only gives Adj Close. We approximate by scaling or just using Raw High/Low.
          // Using raw High/Low with Adj Close can be mismatched, but it's the standard limitation.
          // However, for pure MA checks, calcCloses is what matters.
          calcHighs.push(highs[i]); 
          calcLows.push(lows[i]);
      }
  });

  // 4. Calculate Indicators using the (potentially Adjusted) Closes
  const ma5 = calculateSMA(calcCloses, 5);
  const ma10 = calculateSMA(calcCloses, 10);
  const ma20 = calculateSMA(calcCloses, 20);
  const ma60 = calculateSMA(calcCloses, 60);
  const rsi = calculateRSI(calcCloses, 14);
  const { macdLine, signalLine, histogram } = calculateMACD(calcCloses);
  const { K, D, J } = calculateKDJ(calcHighs, calcLows, calcCloses);

  const fullProcessedData: StockDataPoint[] = cleanData.map((d, i) => {
      const getDir = (current: number | undefined, prev: number | undefined) => {
          if (current === undefined || prev === undefined) return 'flat';
          return current > prev ? 'up' : current < prev ? 'down' : 'flat';
      };

      const chips = chipMap.get(d.date) || { foreign: 0, trust: 0 };

      return {
          ...d,
          ma5: ma5[i] || undefined,
          ma10: ma10[i] || undefined,
          ma20: ma20[i] || undefined,
          ma60: ma60[i] || undefined,
          ma5Dir: i > 0 ? getDir(ma5[i], ma5[i-1]) : 'flat',
          ma10Dir: i > 0 ? getDir(ma10[i], ma10[i-1]) : 'flat',
          ma20Dir: i > 0 ? getDir(ma20[i], ma20[i-1]) : 'flat',
          ma60Dir: i > 0 ? getDir(ma60[i], ma60[i-1]) : 'flat',

          rsi: rsi[i] || undefined,
          macd: macdLine[i] || undefined,
          macdSignal: signalLine[i] || undefined,
          macdHist: histogram[i] || undefined,
          k: K[i],
          d: D[i],
          j: J[i],

          foreignBuySell: chips.foreign, 
          investmentTrustBuySell: chips.trust
      };
  });

  let displayName = meta.longName || meta.shortName || meta.symbol;
  if (isTaiwanStock && taiwanStockName) {
      displayName = taiwanStockName;
  }

  return {
      info: {
          symbol: meta.symbol,
          name: displayName,
          currency: meta.currency,
          exchangeTimezoneName: meta.exchangeTimezoneName
      },
      data: fullProcessedData
  };
};

