  const [analysis, setAnalysis] = useState<string>('');

  // Indicator Settings State
  const [indicatorSettings, setIndicatorSettings] = useState<IndicatorSettings>({
    showMA5: true,
    showMA10: true,
    showMA20: true,
    showMA60: true,
    showRSI: true,
    showK: true,
    showD: true,
    showJ: true,
