// CRITICAL: Format date based on Exchange Timezone to match Yahoo Web
const formatExchangeDate = (timestamp: number, timezone: string, interval: TimeInterval) => {
    const date = new Date(timestamp * 1000);
    const isIntraday = interval.includes('m');

    try {
        const options: Intl.DateTimeFormatOptions = {
            timeZone: timezone,
            year: 'numeric',
            month: '2-digit',
            day: '2-digit',
            hour: isIntraday ? '2-digit' : undefined,
            minute: isIntraday ? '2-digit' : undefined,
            hour12: false
        };
        const formatter = new Intl.DateTimeFormat('en-US', options);
        const parts = formatter.formatToParts(date);

        const p: any = {};
        parts.forEach(({type, value}) => p[type] = value);

        // Return strictly formatted string
        if (isIntraday) {
            return `${p.month}-${p.day} ${p.hour}:${p.minute}`;
        } else {
            return `${p.year}-${p.month}-${p.day}`;
        }
    } catch (e) {
        // Fallback for invalid timezones
        const d = new Date(timestamp * 1000);
        const iso = d.toISOString();
        return isIntraday ? iso.slice(5, 16).replace('T', ' ') : iso.slice(0, 10);
    }
};

const fetchRawData = async (symbol: string, interval: TimeInterval) => {
  let range = '10y';

  switch (interval) {
      case '15m':
          range = '60d'; // Max allowable for 15m
          break;
      case '60m':
          range = '1y'; // 1y is safer for 60m data integrity
          break;
      case '1d':
          range = '10y'; 
          break;
      case '1wk':
          range = '10y'; // 10y is sufficient and faster than max for Weekly
          break;
      case '1mo':
          range = 'max'; // Max needed for Monthly long trends
          break;
      default:
          range = '5y';
  }

  const cleanSymbol = symbol.trim().toUpperCase();
  const looksLikeTaiwanStock = /[0-9]/.test(cleanSymbol);

  if (looksLikeTaiwanStock) {
      const target = cleanSymbol.replace('.TW', '').replace('.TWO', '');
      try {
          return await queryYahoo(`${target}.TW`, interval, range);
      } catch (e) {
          console.log(`Failed to fetch ${target}.TW, trying .TWO`);
          return await queryYahoo(`${target}.TWO`, interval, range);
      }
  } else {
      try {
          return await queryYahoo(cleanSymbol, interval, range);
      } catch (e) {
          try {
             return await queryYahoo(`${cleanSymbol}.TW`, interval, range);
          } catch {
             return await queryYahoo(`${cleanSymbol}.TWO`, interval, range);
          }
      }
  }
};

