// Helper: Get Monday of the week using UTC to avoid DST issues
function getMondayUTC(year: number, month: number, day: number) {
    // Create UTC date to avoid timezone offsets shifting the day
    const date = new Date(Date.UTC(year, month, day));
    const dayOfWeek = date.getUTCDay(); // 0 (Sun) - 6 (Sat)
    // Adjust to Monday (1)
    // If Sun (0): diff = -6. Mon (1): diff = 0. Tue (2): diff = -1.
    const diff = date.getUTCDate() - dayOfWeek + (dayOfWeek === 0 ? -6 : 1);
    date.setUTCDate(diff);
    return date;
}

function aggregateData(dailyData: any[], interval: TimeInterval) {
    // 1. Sort daily data by time to ensure correct First/Last logic
    dailyData.sort((a, b) => a.timestamp - b.timestamp);

    const groups = new Map<string, any>();

    dailyData.forEach(day => {
        // Parse the Exchange-Formatted Date String (YYYY-MM-DD)
        const dateParts = day.date.split('-'); 
        if(dateParts.length < 3) return;

        const year = parseInt(dateParts[0]);
        const month = parseInt(dateParts[1]) - 1; // 0-indexed
        const dateNum = parseInt(dateParts[2]);

        let key = '';
        if (interval === '1mo') {
            // Key: YYYY-MM-01
            key = `${year}-${String(month+1).padStart(2, '0')}-01`;
        } else if (interval === '1wk') {
            // Key: Monday of the week
            const monday = getMondayUTC(year, month, dateNum);
            key = `${monday.getUTCFullYear()}-${String(monday.getUTCMonth()+1).padStart(2, '0')}-${String(monday.getUTCDate()).padStart(2, '0')}`;
        } else {
            return;
        }

        if (!groups.has(key)) {
            // Initialize group with the FIRST day's data (Open, Low, High, Close)
            // This ensures Open = First Trading Day's Open
            groups.set(key, {
                date: key, 
                timestamp: day.timestamp, // Start timestamp of period
                open: day.open,
                high: day.high,
                low: day.low,
                close: day.close,
                volume: 0,
                openAdj: day.openAdj,
                highAdj: day.highAdj,
                lowAdj: day.lowAdj,
                closeAdj: day.closeAdj,
                foreignBuySell: 0,
                investmentTrustBuySell: 0
            });
        }

        const group = groups.get(key);

        // Update High/Low (Max/Min of the period)
        group.high = Math.max(group.high, day.high);
        group.low = Math.min(group.low, day.low);
        group.highAdj = Math.max(group.highAdj, day.highAdj);
        group.lowAdj = Math.min(group.lowAdj, day.lowAdj);

        // Update Close: Always overwrite with the current day. 
        // Since we sorted by date, the last update will be the Last Trading Day's Close.
        group.close = day.close;
        group.closeAdj = day.closeAdj;

        // Accumulate Volume and Chips
        group.volume += day.volume;
        group.foreignBuySell += (day.foreignBuySell || 0);
        group.investmentTrustBuySell += (day.investmentTrustBuySell || 0);
    });

    return Array.from(groups.values());
}

