1. 新增穩定版的 getWeekStartDate 函數
請將原本的 getMonday 函數替換為以下版本。這個版本會將時間固定在中午 12:00，避免因為日光節約時間或時區導致日期在 00:00 往前跳一天，確保「星期一」的計算絕對準確。

TypeScript

// 用此函數取代原本的 getMonday，邏輯更穩健
function getWeekStartDate(dateStr: string): string {
    // 輸入格式為 YYYY-MM-DD
    const parts = dateStr.split('-').map(Number);
    // 建立日期物件時設定為中午 12:00:00，避免時區導致日期偏移
    const d = new Date(parts[0], parts[1] - 1, parts[2], 12, 0, 0);

    const day = d.getDay(); // 0 (週日) ~ 6 (週六)
    // 計算與週一 (1) 的差距
    // 若是週日(0)，則回推 6 天到上週一
    // 若是週一(1)，回推 0 天
    // 若是週二(2)，回推 1 天...
    const diff = day === 0 ? -6 : 1 - day;

    d.setDate(d.getDate() + diff);

    const y = d.getFullYear();
    const m = String(d.getMonth() + 1).padStart(2, '0');
    const da = String(d.getDate()).padStart(2, '0');

    return `${y}-${m}-${da}`; // 回傳標準 YYYY-MM-DD 格式
}
2. 更新 aggregateData 函數
請更新 aggregateData 函數，直接使用上述的新函數來生成 Key，並確保邏輯簡潔。

TypeScript

function aggregateData(dailyData: any[], interval: TimeInterval) {
    const groups = new Map<string, any>();

    // 依序處理每一筆日資料
    dailyData.forEach(day => {
        // 確保日期字串存在
        if (!day.date) return;

        let key = '';

        if (interval === '1mo') {
            // 月線邏輯：取該月 1 號 (YYYY-MM-01)
            const parts = day.date.split('-');
            key = `${parts[0]}-${parts[1]}-01`;
        } else if (interval === '1wk') {
            // 週線邏輯：直接算出該週的星期一日期
            key = getWeekStartDate(day.date);
        } else {
            // 若非週/月，不進行聚合 (理論上不會進到這裡，因為外部已過濾)
            return;
        }

        if (!groups.has(key)) {
            groups.set(key, {
                date: key, 
                timestamp: day.timestamp, // 使用該週/月第一筆資料的時間戳
                open: day.open,
                high: day.high,
                low: day.low,
                close: day.close,
                volume: 0,
                openAdj: day.openAdj,
                highAdj: day.highAdj,
                lowAdj: day.lowAdj,
                closeAdj: day.closeAdj,
                foreignBuySell: 0,
                investmentTrustBuySell: 0
            });
        }

        const group = groups.get(key);

        // 更新最高/最低價
        group.high = Math.max(group.high, day.high);
        group.low = Math.min(group.low, day.low);
        group.highAdj = Math.max(group.highAdj, day.highAdj);
        group.lowAdj = Math.min(group.lowAdj, day.lowAdj);

        // 收盤價永遠取最新的一筆 (因為 dailyData 是按時間排序的)
        group.close = day.close;
        group.closeAdj = day.closeAdj;

        // 累加成交量與籌碼
        group.volume += day.volume;
        group.foreignBuySell += (day.foreignBuySell || 0);
        group.investmentTrustBuySell += (day.investmentTrustBuySell || 0);
    });

    // 轉回陣列並依日期排序
    return Array.from(groups.values()).sort((a, b) => {
        return new Date(a.date).getTime() - new Date(b.date).getTime();
    });
}

