        return (json.msg === 'success' && Array.isArray(json.data) && json.data.length > 0) ? json.data[0].stock_name : null;
    } catch (e) {
        console.warn("Failed to fetch stock info from FinMind", e);
        return null;
    }
};

// CRITICAL: Format date based on Exchange Timezone
const formatExchangeDate = (timestamp: number, timezone: string, interval: string) => {
    const date = new Date(timestamp * 1000);
    // If we are fetching '1d' data for '1wk' aggregation, we treat it as daily (no time)
    // The queryInterval passed here will be '1d' in that case.
    const isIntraday = interval.includes('m'); 

    try {
        const options: Intl.DateTimeFormatOptions = {
            timeZone: timezone,
            year: 'numeric',
            month: '2-digit',
            day: '2-digit',
            hour: isIntraday ? '2-digit' : undefined,
            minute: isIntraday ? '2-digit' : undefined,
            hour12: false
        };
        const formatter = new Intl.DateTimeFormat('en-US', options);
        const parts = formatter.formatToParts(date);

        const p: any = {};
        parts.forEach(({type, value}) => p[type] = value);

        if (isIntraday) {
            return `${p.month}-${p.day} ${p.hour}:${p.minute}`;
        } else {
            return `${p.year}-${p.month}-${p.day}`;
        }
    } catch (e) {
        const d = new Date(timestamp * 1000);
        const iso = d.toISOString();
        return isIntraday ? iso.slice(5, 16).replace('T', ' ') : iso.slice(0, 10);
    }
};

const queryYahoo = async (symbol: string, interval: string, range: string): Promise<YahooChartResponse> => {
    // includePrePost=false is CRITICAL for Intraday accuracy
    const url = `${CORS_PROXY}${encodeURIComponent(`${YAHOO_BASE}${symbol}?interval=${interval}&range=${range}&includeAdjustedClose=true&includePrePost=false&lang=zh-Hant-TW&region=TW`)}`;
    const res = await fetch(url);
    if (!res.ok) throw new Error(`Fetch error: ${res.statusText}`);
    const json = await res.json();
    if (json.chart.error) throw new Error(JSON.stringify(json.chart.error));
    if (!json.chart.result || json.chart.result.length === 0) throw new Error('No data found');
    return json as YahooChartResponse;
};

// Fetch Logic with Aggregation Strategy
const fetchRawData = async (symbol: string, interval: TimeInterval) => {
  let queryInterval = interval as string;
  let range = '10y';

  // STRATEGY: Fetch Daily MAX for Weekly/Monthly aggregation to ensure accuracy
  if (interval === '1wk' || interval === '1mo') {
      queryInterval = '1d';
      range = 'max';
  } else if (interval === '60m') {
      range = '1y'; // 1y is safe max for 60m
  } else if (interval === '15m') {
      range = '60d';
  } else if (interval === '1d') {
      range = '10y';
  }

  const cleanSymbol = symbol.trim().toUpperCase();
  const looksLikeTaiwanStock = /[0-9]/.test(cleanSymbol);

  const performQuery = async (s: string) => queryYahoo(s, queryInterval, range);

  if (looksLikeTaiwanStock) {
      const target = cleanSymbol.replace('.TW', '').replace('.TWO', '');
      try {
          const res = await performQuery(`${target}.TW`);
          return { response: res, actualInterval: queryInterval };
      } catch (e) {
          console.log(`Failed to fetch ${target}.TW, trying .TWO`);
          const res = await performQuery(`${target}.TWO`);
          return { response: res, actualInterval: queryInterval };
      }
  } else {
      try {
          const res = await performQuery(cleanSymbol);
          return { response: res, actualInterval: queryInterval };
      } catch (e) {
          try {
             const res = await performQuery(`${cleanSymbol}.TW`);
             return { response: res, actualInterval: queryInterval };
          } catch {
             const res = await performQuery(`${cleanSymbol}.TWO`);
             return { response: res, actualInterval: queryInterval };
          }
      }
  }
};

// 用此函數取代原本的 getMonday，邏輯更穩健
function getWeekStartDate(dateStr: string): string {
    // 輸入格式為 YYYY-MM-DD
    const parts = dateStr.split('-').map(Number);
    // 建立日期物件時設定為中午 12:00:00，避免時區導致日期偏移
    const d = new Date(parts[0], parts[1] - 1, parts[2], 12, 0, 0);

    const day = d.getDay(); // 0 (週日) ~ 6 (週六)
    // 計算與週一 (1) 的差距
    // 若是週日(0)，則回推 6 天到上週一
    // 若是週一(1)，回推 0 天
    // 若是週二(2)，回推 1 天...
    const diff = day === 0 ? -6 : 1 - day;

    d.setDate(d.getDate() + diff);

    const y = d.getFullYear();
    const m = String(d.getMonth() + 1).padStart(2, '0');
    const da = String(d.getDate()).padStart(2, '0');

    return `${y}-${m}-${da}`; // 回傳標準 YYYY-MM-DD 格式
}

function aggregateData(dailyData: any[], interval: TimeInterval) {
    // 1. Sort daily data by time to ensure correct First/Last logic (kept from previous logic for safety)
    dailyData.sort((a, b) => a.timestamp - b.timestamp);

    const groups = new Map<string, any>();

    // 依序處理每一筆日資料
    dailyData.forEach(day => {
        // 確保日期字串存在
        if (!day.date) return;

        let key = '';

        if (interval === '1mo') {
            // 月線邏輯：取該月 1 號 (YYYY-MM-01)
            const parts = day.date.split('-');
            if (parts.length >= 2) {
                key = `${parts[0]}-${parts[1]}-01`;
            } else {
                return;
            }
        } else if (interval === '1wk') {
            // 週線邏輯：直接算出該週的星期一日期
            key = getWeekStartDate(day.date);
        } else {
            // 若非週/月，不進行聚合 (理論上不會進到這裡，因為外部已過濾)
            return;
        }

