    if (!json.chart.result || json.chart.result.length === 0) throw new Error('No data found');
    return json as YahooChartResponse;
};

// Fetch Logic with Direct Intervals (No Aggregation)
const fetchRawData = async (symbol: string, interval: TimeInterval) => {
  let queryInterval = interval as string;
  let range = '5y'; // Default useful range

  // STRATEGY: Use Native Yahoo Intervals directly
  if (interval === '1wk') {
      queryInterval = '1wk';
      range = '5y'; 
  } else if (interval === '1mo') {
      queryInterval = '1mo';
      range = 'max'; 
  } else if (interval === '1d') {
      range = '10y';
  } else if (interval === '60m') {
      // SPECIAL HANDLING FOR 60m (1H):
      // Yahoo often drops the last 30mins (13:00-13:30) of TW stocks if we ask for 60m.
      // Strategy: Fetch 30m data and manually aggregate to 60m.
      queryInterval = '30m';
      range = '3mo'; // 30m data is heavy, 3mo is sufficient for hourly analysis
  } else if (interval === '15m') {
      range = '60d';
  } else if (interval === '15m') { 
      // fallback
      range = '60d';
  }

  const cleanSymbol = symbol.trim().toUpperCase();
  const looksLikeTaiwanStock = /[0-9]/.test(cleanSymbol);

  const performQuery = async (s: string) => queryYahoo(s, queryInterval, range);

  if (looksLikeTaiwanStock) {
      const target = cleanSymbol.replace('.TW', '').replace('.TWO', '');
      try {
          const res = await performQuery(`${target}.TW`);
          return { response: res, actualInterval: queryInterval };
      } catch (e) {
          console.log(`Failed to fetch ${target}.TW, trying .TWO`);
          const res = await performQuery(`${target}.TWO`);
          return { response: res, actualInterval: queryInterval };
      }
  } else {
      try {
          const res = await performQuery(cleanSymbol);
          return { response: res, actualInterval: queryInterval };
      } catch (e) {
          try {
             const res = await performQuery(`${cleanSymbol}.TW`);
             return { response: res, actualInterval: queryInterval };
          } catch {
             const res = await performQuery(`${cleanSymbol}.TWO`);
             return { response: res, actualInterval: queryInterval };
          }
      }
  }
};

// Aggregation Helper: 30m -> 60m
const aggregate30mTo60m = (data: any[]) => {
    const groups = new Map<number, any>();

    data.forEach(d => {
        // Group by Hour Start (UTC based logic works for standard offsets)
        // This effectively groups XX:00 and XX:30 into XX:00
        const hourKey = Math.floor(d.timestamp / 3600) * 3600;

        if (!groups.has(hourKey)) {
            // First partial bar of the hour (e.g. 09:00 or 09:30 or 13:00)
            groups.set(hourKey, {
                ...d,
                timestamp: hourKey, // normalize timestamp to hour start
                // We keep the 'date' string of the *first* bar encountered in this hour.
                // For TW: 09:00 bar sets the date string "09:00". 09:30 merges into it.
                // For TW: 13:00 bar sets the date string "13:00". No 13:30 bar exists.
            });
        } else {
            const g = groups.get(hourKey);
            g.high = Math.max(g.high, d.high);
            g.low = Math.min(g.low, d.low);
            g.close = d.close; // Close is always the latest
            g.volume += d.volume; // Sum volume

            // Handle Adj
            g.highAdj = Math.max(g.highAdj || 0, d.highAdj || 0);
            g.lowAdj = Math.min(g.lowAdj || 0, d.lowAdj || 0);
            g.closeAdj = d.closeAdj;

            // Handle Chips
            g.foreignBuySell = (g.foreignBuySell || 0) + (d.foreignBuySell || 0);
            g.investmentTrustBuySell = (g.investmentTrustBuySell || 0) + (d.investmentTrustBuySell || 0);
        }
    });

    return Array.from(groups.values());
};

export const getStockData = async (symbol: string, interval: TimeInterval = '1d'): Promise<{info: StockInfo, data: StockDataPoint[]}> => {
  // 1. Fetch from Yahoo
  // Note: if interval is '1wk', we get '1wk'. If '60m', we actually fetch '30m' inside.
  const { response, actualInterval } = await fetchRawData(symbol, interval);

  const result = response.chart.result![0];
  const meta = result.meta;
  const timestamps = result.timestamp;
  const quote = result.indicators.quote[0];
  const adjCloseRaw = result.indicators.adjclose?.[0]?.adjclose; 

  if (!timestamps || !quote || !quote.close) {
      throw new Error("Invalid data structure received from API");
  }

  const closes = quote.close;
  const opens = quote.open;
  const highs = quote.high;
  const lows = quote.low;
  const volumes = quote.volume; 

  const isTaiwanStock = meta.symbol.endsWith('.TW') || meta.symbol.endsWith('.TWO');

  // 2. Fetch FinMind Data 
  const shouldFetchFinMind = isTaiwanStock && interval === '1d';

  const chipMap = new Map<string, { foreign: number, trust: number }>();
  const volumeMap = new Map<string, number>();
  let taiwanStockName: string | null = null;

  if (shouldFetchFinMind) {
      const fetchedName = await fetchFinMindStockInfo(meta.symbol);
      if (fetchedName) taiwanStockName = fetchedName;

      let fetchStartDate = new Date();
      fetchStartDate.setFullYear(fetchStartDate.getFullYear() - 5); 
      const fetchStartDateStr = fetchStartDate.toISOString().split('T')[0];

      const [institutionalData, finMindPriceData] = await Promise.all([
          fetchInstitutionalData(meta.symbol, fetchStartDateStr),
          fetchFinMindPriceVolume(meta.symbol, fetchStartDateStr),
      ]);

      institutionalData.forEach((item: any) => {
          const date = item.date; 
          const net = (item.buy || 0) - (item.sell || 0);
          if (!chipMap.has(date)) chipMap.set(date, { foreign: 0, trust: 0 });
          const record = chipMap.get(date)!;
          if (item.name === 'Foreign_Investor') record.foreign += net;
          else if (item.name === 'Investment_Trust') record.trust += net;
      });

      finMindPriceData.forEach((item: any) => {
          volumeMap.set(item.date, item.Trading_Volume); 
      });
  }

  // 3. Process Data
  const cleanData: any[] = [];
  const nowTs = Math.floor(Date.now() / 1000);

  timestamps.forEach((ts, i) => {
      // Basic validation
      if (closes[i] !== null && opens[i] !== null && highs[i] !== null && lows[i] !== null) {

          let displayTs = ts;
          // For Weekly Interval: Show Date as Friday (End of Week) or Today (if current week)
          if (actualInterval === '1wk') {
             const fridayTs = ts + (4 * 24 * 60 * 60); // Monday + 4 days
             displayTs = Math.min(fridayTs, nowTs);
          }

          const useIntervalForFormat = actualInterval === '1wk' ? '1d' : actualInterval;
          const dateStr = formatExchangeDate(displayTs, meta.exchangeTimezoneName, useIntervalForFormat);

          let finalVolume = 0;
          if (shouldFetchFinMind && volumeMap.has(dateStr)) {
              finalVolume = volumeMap.get(dateStr)!;
          } else {
              finalVolume = (volumes && volumes[i]) ? volumes[i] : 0;
          }

          const rawC = closes[i];
          const adjC = (adjCloseRaw && adjCloseRaw[i]) ? adjCloseRaw[i] : rawC;
          const ratio = (rawC !== 0) ? adjC / rawC : 1;

          const chips = chipMap.get(dateStr) || { foreign: 0, trust: 0 };

          cleanData.push({
              date: dateStr,
              timestamp: ts,
              open: opens[i],
              high: highs[i],
              low: lows[i],
              close: rawC,
              volume: finalVolume,
              // Store Adjusted OHLC
              openAdj: opens[i] * ratio,
              highAdj: highs[i] * ratio,
              lowAdj: lows[i] * ratio,
              closeAdj: adjC,
              foreignBuySell: chips.foreign,
              investmentTrustBuySell: chips.trust
          });
      }
  });

  // 4. Final Data Processing
  let finalData = cleanData;

  // AGGREGATION: If we requested 60m but fetched 30m, aggregate it now.
  if (interval === '60m' && actualInterval === '30m') {
      finalData = aggregate30mTo60m(cleanData);
  }

  // 5. Calculate Indicators on FINAL data
  const rawCloses = finalData.map(d => d.close);
  const rawHighs = finalData.map(d => d.high);
  const rawLows = finalData.map(d => d.low);
  const adjCloses = finalData.map(d => d.closeAdj);

  // Set A: RAW
  const ma5 = calculateSMA(rawCloses, 5);
  const ma10 = calculateSMA(rawCloses, 10);
  const ma20 = calculateSMA(rawCloses, 20);
  const ma60 = calculateSMA(rawCloses, 60);
  const rsi = calculateRSI(rawCloses, 14);
  const { macdLine, signalLine, histogram } = calculateMACD(rawCloses);
  const { K, D, J } = calculateKDJ(rawHighs, rawLows, rawCloses);

  // Set B: ADJUSTED
  const ma5Adj = calculateSMA(adjCloses, 5);
  const ma10Adj = calculateSMA(adjCloses, 10);
  const ma20Adj = calculateSMA(adjCloses, 20);
  const ma60Adj = calculateSMA(adjCloses, 60);
  const rsiAdj = calculateRSI(adjCloses, 14);
  const macdDataAdj = calculateMACD(adjCloses);

  const fullProcessedData: StockDataPoint[] = finalData.map((d: any, i: number) => {
      const getDir = (current: number | undefined, prev: number | undefined) => {
          if (current === undefined || prev === undefined) return 'flat';
          return current > prev ? 'up' : current < prev ? 'down' : 'flat';
      };

      const prevClose = i > 0 ? finalData[i-1].close : d.open;
      const priceChange = d.close - prevClose;
      const priceChangePercent = (priceChange / prevClose) * 100;

      return {
          ...d,
          // Raw
          ma5: ma5[i] || undefined,
          ma10: ma10[i] || undefined,
          ma20: ma20[i] || undefined,
          ma60: ma60[i] || undefined,
          ma5Dir: i > 0 ? getDir(ma5[i], ma5[i-1]) : 'flat',
          ma10Dir: i > 0 ? getDir(ma10[i], ma10[i-1]) : 'flat',
          ma20Dir: i > 0 ? getDir(ma20[i], ma20[i-1]) : 'flat',
          ma60Dir: i > 0 ? getDir(ma60[i], ma60[i-1]) : 'flat',
          rsi: rsi[i] || undefined,
          macd: macdLine[i] || undefined,
          macdSignal: signalLine[i] || undefined,
          macdHist: histogram[i] || undefined,
          k: K[i],
          d: D[i],
          j: J[i],

          // Adjusted
          ma5Adj: ma5Adj[i] || undefined,
          ma10Adj: ma10Adj[i] || undefined,
          ma20Adj: ma20Adj[i] || undefined,
          ma60Adj: ma60Adj[i] || undefined,
          rsiAdj: rsiAdj[i] || undefined,
          macdAdj: macdDataAdj.macdLine[i] || undefined,
          macdSignalAdj: macdDataAdj.signalLine[i] || undefined,
          macdHistAdj: macdDataAdj.histogram[i] || undefined,

          priceChange,
          priceChangePercent
      };
  });

  let displayName = meta.longName || meta.shortName || meta.symbol;
  if (isTaiwanStock && taiwanStockName) {
      displayName = taiwanStockName;
  }

  return {
      info: {
          symbol: meta.symbol,
          name: displayName,
          currency: meta.currency,
          exchangeTimezoneName: meta.exchangeTimezoneName
      },
      data: fullProcessedData
  };
};

