    orientation: "right" as const,
    width: Y_AXIS_WIDTH,
    tick: { fontSize: 11, fill: '#94a3b8' },
    tickLine: false,
    axisLine: false,
    mirror: false,
    tickMargin: 5,
  };

  if (!data || data.length === 0) return <div className="text-gray-400">No data available for chart</div>;

