// Format date based on Exchange Timezone
const formatExchangeDate = (timestamp: number, timezone: string, interval: string) => {
    const date = new Date(timestamp * 1000);
    const isIntraday = interval.includes('m'); 

    try {
        const options: Intl.DateTimeFormatOptions = {
            timeZone: timezone,
            year: 'numeric',
            month: '2-digit',
            day: '2-digit',
            hour: isIntraday ? '2-digit' : undefined,
            minute: isIntraday ? '2-digit' : undefined,
            hour12: false
        };
        const formatter = new Intl.DateTimeFormat('en-US', options);
        const parts = formatter.formatToParts(date);

        const p: any = {};
        parts.forEach(({type, value}) => p[type] = value);

        if (isIntraday) {
            // Ensure 2 digits for consistency
            const h = p.hour.padStart(2, '0');
            const m = p.minute.padStart(2, '0');
            return `${p.month}-${p.day} ${h}:${m}`;
        } else {
            return `${p.year}-${p.month}-${p.day}`;
        }
    } catch (e) {
        const d = new Date(timestamp * 1000);
        const iso = d.toISOString();
        return isIntraday ? iso.slice(5, 16).replace('T', ' ') : iso.slice(0, 10);
    }
};

// Retrieve specific time parts in Exchange Timezone
const getExchangeTime = (timestamp: number, timezone: string, isTaiwan: boolean): { hour: number, minute: number } => {
    try {
        // FORCE Asia/Taipei for Taiwan stocks to avoid browser/server timezone mismatch
        const effectiveTimezone = isTaiwan ? 'Asia/Taipei' : timezone;

        const date = new Date(timestamp * 1000);
        const options: Intl.DateTimeFormatOptions = {
            timeZone: effectiveTimezone,
            hour: 'numeric',
            minute: 'numeric',
            hour12: false
        };
        const formatter = new Intl.DateTimeFormat('en-US', options);
        const parts = formatter.formatToParts(date);

        let h = 0, m = 0;
        parts.forEach(p => {
            if(p.type === 'hour') h = parseInt(p.value, 10);
            if(p.type === 'minute') m = parseInt(p.value, 10);
        });

        // Handle 24:00 edge case if any (unlikely in this context)
        if (h === 24) h = 0;

        return { hour: h, minute: m };
    } catch (e) {
        const d = new Date(timestamp * 1000);
        return { hour: d.getHours(), minute: d.getMinutes() };
    }
};

