                        <>
                        <span className="text-yellow-400 font-bold">K (9)</span>
                        <span className="text-slate-200">{data.k?.toFixed(2)}</span>
                        </>
                    )}

                    {settings.showD && (
                        <>
                        <span className="text-pink-400 font-bold">D (9)</span>
                        <span className="text-slate-200">{data.d?.toFixed(2)}</span>
                        </>
