// ----------------------------------------------------------------------
// 2. Info Overlay Component
// ----------------------------------------------------------------------

const MALegend = ({ currentData, settings }: { currentData: StockDataPoint, settings: IndicatorSettings }) => {
    if (!currentData) return null;

    const renderItem = (label: string, value: number | undefined, dir: string | undefined, color: string) => {
        if (value === undefined) return null;
        const arrow = dir === 'up' ? '▲' : dir === 'down' ? '▼' : ''; 
        const dirColor = dir === 'up' ? 'text-red-400' : dir === 'down' ? 'text-emerald-400' : 'text-slate-500';

        return (
            <div className="flex items-center gap-1.5 text-xs font-mono bg-slate-900/50 px-2 py-1 rounded border border-slate-800">
                <span style={{ color: color }} className="font-bold">{label}</span>
                <span className="text-slate-200">{value.toFixed(2)}</span>
                <span className={`${dirColor} text-[10px]`}>{arrow}</span>
            </div>
        );
    };

    return (
        <div className="flex flex-wrap gap-2 items-center">
            {settings.showMA5 && renderItem("MA5", currentData.ma5, currentData.ma5Dir, "#fbbf24")}
            {settings.showMA10 && renderItem("MA10", currentData.ma10, currentData.ma10Dir, "#38bdf8")}
            {settings.showMA20 && renderItem("MA20", currentData.ma20, currentData.ma20Dir, "#a78bfa")}
            {settings.showMA60 && renderItem("MA60", currentData.ma60, currentData.ma60Dir, "#34d399")}
        </div>
    );
};

// ----------------------------------------------------------------------
// 3. Main Chart Component
// ----------------------------------------------------------------------

const StockChart: React.FC<StockChartProps> = ({ data, settings, isTaiwanStock }) => {
  const [activeIndex, setActiveIndex] = useState<number | null>(null);
  const [barsToShow, setBarsToShow] = useState(100);

  useEffect(() => {
     setBarsToShow(Math.min(100, data.length));
  }, [data.length]);

  const handleZoom = (direction: 'in' | 'out') => {
      setBarsToShow(prev => {
          const step = Math.ceil(prev * 0.2); 
          if (direction === 'in') return Math.max(20, prev - step);
          else return Math.min(data.length, prev + step); 
      });
  };

  const hasChipData = useMemo(() => {
      if (!data || data.length === 0) return false;
      return data.some(d => (d.foreignBuySell !== undefined && d.foreignBuySell !== 0) || (d.investmentTrustBuySell !== undefined && d.investmentTrustBuySell !== 0));
  }, [data]);

  const displayData = useMemo(() => {
    const startIndex = Math.max(0, data.length - barsToShow);
    const sliced = data.slice(startIndex);

    if (settings.useAdjusted) {
        return sliced.map(d => ({
            ...d,
            open: d.openAdj !== undefined ? d.openAdj : d.open,
            high: d.highAdj !== undefined ? d.highAdj : d.high,
            low: d.lowAdj !== undefined ? d.lowAdj : d.low,
            close: d.closeAdj !== undefined ? d.closeAdj : d.close,
            ma5: d.ma5Adj !== undefined ? d.ma5Adj : d.ma5,
            ma10: d.ma10Adj !== undefined ? d.ma10Adj : d.ma10,
            ma20: d.ma20Adj !== undefined ? d.ma20Adj : d.ma20,
            ma60: d.ma60Adj !== undefined ? d.ma60Adj : d.ma60,
            rsi: d.rsiAdj !== undefined ? d.rsiAdj : d.rsi,
            macd: d.macdAdj !== undefined ? d.macdAdj : d.macd,
            macdSignal: d.macdSignalAdj !== undefined ? d.macdSignalAdj : d.macdSignal,
            macdHist: d.macdHistAdj !== undefined ? d.macdHistAdj : d.macdHist
        }));
    }
    return sliced;
  }, [data, barsToShow, settings.useAdjusted]);

  const currentData = activeIndex !== null && displayData[activeIndex] ? displayData[activeIndex] : displayData[displayData.length - 1];

  if (!data || data.length === 0) return <div className="text-white">No data</div>;

  return (
    <div className="space-y-4">
      {/* Price Chart */}
      <div className="bg-slate-800 rounded-xl p-4 border border-slate-700 shadow-xl relative">
        <div className="flex justify-between items-center mb-4">
            <h3 className="text-slate-400 text-sm font-bold uppercase tracking-wider flex items-center gap-2">
                Price / Volume / MA
                {settings.useAdjusted && <span className="bg-indigo-500/20 text-indigo-300 text-[10px] px-1.5 py-0.5 rounded border border-indigo-500/30">Adj</span>}
            </h3>

            {/* Legend Overlay */}
            <div className="absolute top-4 left-1/2 -translate-x-1/2 hidden md:block z-10">
                <MALegend currentData={currentData} settings={settings} />
            </div>

            <div className="flex gap-2">
                <button onClick={() => handleZoom('out')} className="p-1.5 rounded-lg bg-slate-700 hover:bg-slate-600 text-slate-300 transition-colors"><ZoomOut size={16} /></button>
                <button onClick={() => handleZoom('in')} className="p-1.5 rounded-lg bg-slate-700 hover:bg-slate-600 text-slate-300 transition-colors"><ZoomIn size={16} /></button>
            </div>
        </div>

        <div className="h-[400px] w-full">
          <ResponsiveContainer width="100%" height="100%">
            <ComposedChart
              data={displayData}
              onMouseMove={(e: any) => {
                if (e.activeTooltipIndex !== undefined) {
                  setActiveIndex(e.activeTooltipIndex);
                }
              }}
              onMouseLeave={() => setActiveIndex(null)}
              barGap={0} // No gap between candles
            >
              <defs>
                 <linearGradient id="volGradientUp" x1="0" y1="0" x2="0" y2="1">
                    <stop offset="5%" stopColor="#f87171" stopOpacity={0.3}/>
                    <stop offset="95%" stopColor="#f87171" stopOpacity={0}/>
                 </linearGradient>
                 <linearGradient id="volGradientDown" x1="0" y1="0" x2="0" y2="1">
                    <stop offset="5%" stopColor="#34d399" stopOpacity={0.3}/>
                    <stop offset="95%" stopColor="#34d399" stopOpacity={0}/>
                 </linearGradient>
              </defs>
              <CartesianGrid strokeDasharray="3 3" stroke="#334155" vertical={false} />
              <XAxis 
                dataKey="date" 
                tick={{ fill: '#94a3b8', fontSize: 10 }} 
                tickLine={false}
                axisLine={{ stroke: '#475569' }}
                minTickGap={30}
              />
              <YAxis 
                yAxisId="price" 
                domain={['auto', 'auto']} 
                tick={{ fill: '#94a3b8', fontSize: 10 }} 
                tickLine={false}
                axisLine={false}
                width={40}
                orientation="right"
              />
              <YAxis 
                yAxisId="volume" 
                orientation="left" 
                tick={false} 
                axisLine={false} 
                width={0}
                domain={[0, (dataMax: number) => dataMax * 4]} // Compress volume to bottom 1/4
              />
              <Tooltip content={<MainTooltip isTaiwanStock={isTaiwanStock} />} cursor={{ stroke: '#64748b', strokeDasharray: '4 4' }} />

              {/* Volume Bars */}
              <Bar 
                dataKey="volume" 
                yAxisId="volume" 
                barSize={Math.max(2, 600 / barsToShow * 0.6)}
                isAnimationActive={false}
              >
                  {displayData.map((entry, index) => (
                      <Cell key={`cell-${index}`} fill={entry.close > entry.open ? "url(#volGradientUp)" : "url(#volGradientDown)"} />
                  ))}
              </Bar>

              {/* Moving Averages */}
              {settings.showMA5 && <Line type="monotone" dataKey="ma5" stroke="#fbbf24" strokeWidth={1} dot={false} yAxisId="price" isAnimationActive={false} />}
              {settings.showMA10 && <Line type="monotone" dataKey="ma10" stroke="#38bdf8" strokeWidth={1} dot={false} yAxisId="price" isAnimationActive={false} />}
              {settings.showMA20 && <Line type="monotone" dataKey="ma20" stroke="#a78bfa" strokeWidth={1} dot={false} yAxisId="price" isAnimationActive={false} />}
              {settings.showMA60 && <Line type="monotone" dataKey="ma60" stroke="#34d399" strokeWidth={1} dot={false} yAxisId="price" isAnimationActive={false} />}

              {/* Candle Stick */}
              <Bar
                dataKey="close" // Dummy key, shape handles OHLC
                shape={<CandleStickShape />}
                yAxisId="price"
                isAnimationActive={false}
                barSize={Math.max(3, 600 / barsToShow * 0.7)}
              >
                {/* Need cells to update color based on logic if not handled in shape? Shape handles it. */}
              </Bar>

            </ComposedChart>
          </ResponsiveContainer>
        </div>
      </div>

       {/* Institutional Chips Chart (Only for Taiwan Stock) */}
       {isTaiwanStock && hasChipData && (
          <div className="bg-slate-800 rounded-xl p-4 border border-slate-700 shadow-xl h-[180px]">
             <h3 className="text-slate-400 text-sm font-bold uppercase tracking-wider mb-2">Institutional Investors (Buy/Sell Net)</h3>
             <ResponsiveContainer width="100%" height="100%">
                 <BarChart data={displayData} barGap={0} syncId="stockSync">
                     <CartesianGrid strokeDasharray="3 3" stroke="#334155" vertical={false} />
                     <XAxis dataKey="date" hide />
                     <YAxis orientation="right" tick={{ fill: '#94a3b8', fontSize: 9 }} width={35} />
                     <Tooltip content={<ChipTooltip title="Foreign" />} cursor={{ fill: '#334155', opacity: 0.2 }} />
                     <ReferenceLine y={0} stroke="#475569" />
                     <Bar dataKey="foreignBuySell" name="Foreign" barSize={Math.max(2, 600 / barsToShow * 0.35)} fill="#ef4444">
                        {displayData.map((entry, index) => (
                             <Cell key={`cell-f-${index}`} fill={entry.foreignBuySell !== undefined && entry.foreignBuySell > 0 ? "#ef4444" : "#10b981"} />
                        ))}
                     </Bar>
                     {/* Add Trust as a second bar or stacked? Side by side is better for net comparison */}
                      <Bar dataKey="investmentTrustBuySell" name="Trust" barSize={Math.max(2, 600 / barsToShow * 0.35)} fill="#3b82f6">
                        {displayData.map((entry, index) => (
                             <Cell key={`cell-t-${index}`} fill={entry.investmentTrustBuySell !== undefined && entry.investmentTrustBuySell > 0 ? "#ef4444" : "#10b981"} />
                        ))}
                     </Bar>
                 </BarChart>
             </ResponsiveContainer>
          </div>
       )}

      {/* RSI Chart */}
      {settings.showRSI && (
          <div className="bg-slate-800 rounded-xl p-4 border border-slate-700 shadow-xl h-[160px]">
            <h3 className="text-slate-400 text-sm font-bold uppercase tracking-wider mb-2">RSI (14)</h3>
            <ResponsiveContainer width="100%" height="100%">
              <ComposedChart data={displayData} syncId="stockSync">
                <CartesianGrid strokeDasharray="3 3" stroke="#334155" vertical={false} />
                <XAxis dataKey="date" hide />
                <YAxis domain={[0, 100]} ticks={[30, 50, 70]} orientation="right" tick={{ fill: '#94a3b8', fontSize: 10 }} width={30} />
                <Tooltip content={<IndicatorTooltip settings={settings} />} cursor={{ stroke: '#64748b', strokeDasharray: '4 4' }} />
                <ReferenceLine y={70} stroke="#ef4444" strokeDasharray="3 3" />
                <ReferenceLine y={30} stroke="#10b981" strokeDasharray="3 3" />
                <Line type="monotone" dataKey="rsi" stroke="#38bdf8" strokeWidth={2} dot={false} isAnimationActive={false} />
              </ComposedChart>
            </ResponsiveContainer>
          </div>
      )}

      {/* MACD Chart */}
      <div className="bg-slate-800 rounded-xl p-4 border border-slate-700 shadow-xl h-[180px]">
        <h3 className="text-slate-400 text-sm font-bold uppercase tracking-wider mb-2">MACD</h3>
        <ResponsiveContainer width="100%" height="100%">
          <ComposedChart data={displayData} syncId="stockSync">
            <CartesianGrid strokeDasharray="3 3" stroke="#334155" vertical={false} />
            <XAxis dataKey="date" hide />
            <YAxis orientation="right" tick={{ fill: '#94a3b8', fontSize: 10 }} width={30} />
            <Tooltip content={<MACDTooltip />} cursor={{ stroke: '#64748b', strokeDasharray: '4 4' }} />
            <Bar dataKey="macdHist" barSize={Math.max(2, 600 / barsToShow * 0.6)} isAnimationActive={false}>
              {displayData.map((entry, index) => (
                <Cell key={`cell-${index}`} fill={(entry.macdHist || 0) >= 0 ? "#ef4444" : "#10b981"} />
              ))}
            </Bar>
            <Line type="monotone" dataKey="macd" stroke="#fb923c" strokeWidth={1} dot={false} isAnimationActive={false} />
            <Line type="monotone" dataKey="macdSignal" stroke="#22d3ee" strokeWidth={1} dot={false} isAnimationActive={false} />
          </ComposedChart>
        </ResponsiveContainer>
      </div>

       {/* KDJ Chart */}
       {(settings.showK || settings.showD || settings.showJ) && (
          <div className="bg-slate-800 rounded-xl p-4 border border-slate-700 shadow-xl h-[160px]">
            <h3 className="text-slate-400 text-sm font-bold uppercase tracking-wider mb-2">KDJ</h3>
            <ResponsiveContainer width="100%" height="100%">
              <ComposedChart data={displayData} syncId="stockSync">
                <CartesianGrid strokeDasharray="3 3" stroke="#334155" vertical={false} />
                <XAxis dataKey="date" hide />
                <YAxis domain={[0, 100]} orientation="right" tick={{ fill: '#94a3b8', fontSize: 10 }} width={30} />
                <Tooltip content={<IndicatorTooltip settings={settings} />} cursor={{ stroke: '#64748b', strokeDasharray: '4 4' }} />
                {settings.showK && <Line type="monotone" dataKey="k" stroke="#facc15" strokeWidth={1.5} dot={false} isAnimationActive={false} />}
                {settings.showD && <Line type="monotone" dataKey="d" stroke="#f472b6" strokeWidth={1.5} dot={false} isAnimationActive={false} />}
                {settings.showJ && <Line type="monotone" dataKey="j" stroke="#c084fc" strokeWidth={1.5} dot={false} isAnimationActive={false} />}
              </ComposedChart>
            </ResponsiveContainer>
          </div>
       )}
    </div>
  );
};

export default StockChart;

import * as React from 'react';
import { useState, useMemo, useEffect } from 'react';
import {
  ComposedChart,
  Line,
  Bar,
  XAxis,
  YAxis,
  CartesianGrid,
  Tooltip,
  ResponsiveContainer,
  BarChart,
  Cell,
  ReferenceLine,
} from 'recharts';
import { StockDataPoint, IndicatorSettings } from '../types';
import { ZoomIn, ZoomOut } from 'lucide-react';

interface StockChartProps {
  data: StockDataPoint[];
  settings: IndicatorSettings;
  isTaiwanStock: boolean;
}

// ----------------------------------------------------------------------
// 1. Custom Shapes & Tooltips
// ----------------------------------------------------------------------

const CandleStickShape = (props: any) => {
  const { x, y, width, height, payload } = props;
  const { open, close, high, low } = payload;

  if (!open || !close) return null;

  const isUp = close > open;
  const isDown = close < open;
  const color = isUp ? '#ef4444' : isDown ? '#10b981' : '#94a3b8';

  const bodyMin = Math.min(open, close);
  const bodyMax = Math.max(open, close);
  const diff = bodyMax - bodyMin;

  let ratio = 0;
  if (diff > 0) {
      ratio = height / diff;
  } else if (height > 0 && (high-low) > 0) {
      // Fallback for doji/flat body but with high/low
      ratio = height / (high - low);
  }

  const yHigh = y - (high - bodyMax) * ratio;
  const yLow = (y + height) + (bodyMin - low) * ratio;
  const centerX = x + width / 2;

  return (
    <g>
      <line x1={centerX} y1={yHigh} x2={centerX} y2={yLow} stroke={color} strokeWidth={1} />
      <rect x={x} y={y} width={width} height={Math.max(1, height)} fill={color} stroke="none" />
    </g>
  );
};

// Main Tooltip for Price/Volume
const MainTooltip = ({ active, payload, label, isTaiwanStock }: any) => {
  if (active && payload && payload.length) {
    const data = payload[0].payload;
    const isUp = data.close > data.open;
    const colorClass = isUp ? "text-red-400" : data.close < data.open ? "text-emerald-400" : "text-slate-400";

    // Display Volume in Lots for Taiwan Stocks
    const volDisplay = isTaiwanStock 
        ? `${Math.round(data.volume / 1000).toLocaleString()} 張`
        : `${(data.volume).toLocaleString()}`; 

    const priceChange = data.priceChange;
    const priceChangePercent = data.priceChangePercent;

    const isChangeUp = priceChange > 0;
    const isChangeDown = priceChange < 0;
    const changeColor = isChangeUp ? "text-red-400" : isChangeDown ? "text-emerald-400" : "text-slate-400";
    const arrow = isChangeUp ? "↑" : isChangeDown ? "↓" : "";
    const changeTxt = priceChange !== undefined ? `${arrow}${Math.abs(priceChange).toFixed(2)}` : '-';
    const percentTxt = priceChangePercent !== undefined ? `${arrow}${Math.abs(priceChangePercent).toFixed(2)}%` : '-';

    return (
      <div className="bg-slate-900 border border-slate-700 p-3 rounded-lg shadow-xl text-xs backdrop-blur-md bg-opacity-90 z-50 min-w-[150px]">
        <p className="text-slate-400 mb-2 font-medium border-b border-slate-700 pb-1">{data.tooltipDate || data.date}</p>
        <div className="grid grid-cols-2 gap-x-4 gap-y-1">
            <span className="text-slate-500">Open</span><span className={colorClass}>{data.open.toFixed(2)}</span>
            <span className="text-slate-500">High</span><span className={colorClass}>{data.high.toFixed(2)}</span>
            <span className="text-slate-500">Low</span><span className={colorClass}>{data.low.toFixed(2)}</span>
            <span className="text-slate-500">Close</span><span className={colorClass}>{data.close.toFixed(2)}</span>

            <span className="text-slate-500">Chg</span><span className={changeColor}>{changeTxt}</span>
            <span className="text-slate-500">Chg%</span><span className={changeColor}>{percentTxt}</span>

            <span className="text-slate-500 col-span-2 border-t border-slate-800 my-1"></span>
            <span className="text-slate-500">Volume</span><span className="text-slate-200">{volDisplay}</span>
        </div>
      </div>
    );
  }
  return null;
};

const ChipTooltip = ({ active, payload, title }: any) => {
    if (active && payload && payload.length) {
        const data = payload[0].payload;
        let val = 0;
        if (title === "Foreign") val = data.foreignBuySell;
        if (title === "Trust") val = data.investmentTrustBuySell;

        const lots = Math.round(val / 1000);
        const colorClass = lots > 0 ? "text-red-400" : lots < 0 ? "text-emerald-400" : "text-slate-400";

        return (
            <div className="bg-slate-900 border border-slate-700 p-3 rounded-lg shadow-xl text-xs backdrop-blur-md bg-opacity-90 z-50">
                <p className="text-slate-400 mb-1 font-medium border-b border-slate-700 pb-1">{data.tooltipDate || data.date}</p>
                <div className="flex justify-between gap-4">
                    <span className="text-slate-300 font-bold">{title}</span>
                    <span className={colorClass}>{lots > 0 ? '+' : ''}{lots.toLocaleString()} 張</span>
                </div>
            </div>
        );
    }
    return null;
}

const IndicatorTooltip = ({ active, payload, settings }: { active?: boolean, payload?: any[], settings: IndicatorSettings }) => {
    if (active && payload && payload.length) {
        const data = payload[0].payload;
        return (
            <div className="bg-slate-900 border border-slate-700 p-3 rounded-lg shadow-xl text-xs backdrop-blur-md bg-opacity-90 z-50">
                <p className="text-slate-400 mb-2 font-medium border-b border-slate-700 pb-1">{data.tooltipDate || data.date}</p>
                <div className="grid grid-cols-2 gap-x-4 gap-y-1">
                    {settings.showRSI && (
                        <>
                            <span className="text-blue-400 font-bold">RSI (14)</span>
                            <span className="text-slate-200">{data.rsi?.toFixed(2)}</span>
                        </>
                    )}

                    {(settings.showK || settings.showD || settings.showJ) && (
                         <div className="col-span-2 border-t border-slate-800 my-1"></div>
                    )}

                    {settings.showK && (
                        <>
                        <span className="text-yellow-400 font-bold">K (9)</span>
                        <span className="text-slate-200">{data.k?.toFixed(2)}</span>
                        </>
                    )}

                    {settings.showD && (
                        <>
                        <span className="text-pink-400 font-bold">D (9)</span>
                        <span className="text-slate-200">{data.d?.toFixed(2)}</span>
                        </>
                    )}

                    {settings.showJ && (
                        <>
                        <span className="text-purple-400 font-bold">J (9)</span>
                        <span className="text-slate-200">{data.j?.toFixed(2)}</span>
                        </>
                    )}
                </div>
            </div>
        );
    }
    return null;
}

const MACDTooltip = ({ active, payload }: any) => {
    if (active && payload && payload.length) {
        const data = payload[0].payload;
        return (
            <div className="bg-slate-900 border border-slate-700 p-3 rounded-lg shadow-xl text-xs backdrop-blur-md bg-opacity-90 z-50">
                <p className="text-slate-400 mb-2 font-medium border-b border-slate-700 pb-1">{data.tooltipDate || data.date}</p>
                <div className="grid grid-cols-2 gap-x-4 gap-y-1">
                    <span className="text-orange-400 font-bold">DIF</span>
                    <span className="text-slate-200">{data.macd?.toFixed(2)}</span>

                    <span className="text-cyan-400 font-bold">DEA</span>
                    <span className="text-slate-200">{data.macdSignal?.toFixed(2)}</span>

                    <span className="text-slate-300 font-bold">Hist</span>
                    <span className={data.macdHist >= 0 ? 'text-red-400' : 'text-emerald-400'}>{data.macdHist?.toFixed(2)}</span>
                </div>
            </div>
        );
    }
    return null;
}

// ----------------------------------------------------------------------
// 2. Info Overlay Component
// ----------------------------------------------------------------------

const MALegend = ({ currentData, settings }: { currentData: StockDataPoint, settings: IndicatorSettings }) => {
    if (!currentData) return null;

    const renderItem = (label: string, value: number | undefined, dir: string | undefined, color: string) => {
        if (value === undefined) return null;
        const arrow = dir === 'up' ? '▲' : dir === 'down' ? '▼' : ''; 
        const dirColor = dir === 'up' ? 'text-red-400' : dir === 'down' ? 'text-emerald-400' : 'text-slate-500';

        return (
            <div className="flex items-center gap-1.5 text-xs font-mono bg-slate-900/50 px-2 py-1 rounded border border-slate-800">
                <span style={{ color: color }} className="font-bold">{label}</span>
                <span className="text-slate-200">{value.toFixed(2)}</span>
                <span className={`${dirColor} text-[10px]`}>{arrow}</span>
            </div>
        );
    };

    return (
        <div className="flex flex-wrap gap-2 items-center">
            {settings.showMA5 && renderItem("MA5", currentData.ma5, currentData.ma5Dir, "#fbbf24")}
            {settings.showMA10 && renderItem("MA10", currentData.ma10, currentData.ma10Dir, "#38bdf8")}
            {settings.showMA20 && renderItem("MA20", currentData.ma20, currentData.ma20Dir, "#a78bfa")}
            {settings.showMA60 && renderItem("MA60", currentData.ma60, currentData.ma60Dir, "#34d399")}
        </div>
    );
};

// ----------------------------------------------------------------------
// 3. Main Chart Component
// ----------------------------------------------------------------------

const StockChart: React.FC<StockChartProps> = ({ data, settings, isTaiwanStock }) => {
  const [activeIndex, setActiveIndex] = useState<number | null>(null);
  const [barsToShow, setBarsToShow] = useState(100);

  useEffect(() => {
     setBarsToShow(Math.min(100, data.length));
  }, [data.length]);

  const handleZoom = (direction: 'in' | 'out') => {
      setBarsToShow(prev => {
          const step = Math.ceil(prev * 0.2); 
          if (direction === 'in') return Math.max(20, prev - step);
          else return Math.min(data.length, prev + step); 
      });
  };

  const hasChipData = useMemo(() => {
      if (!data || data.length === 0) return false;
      return data.some(d => (d.foreignBuySell !== undefined && d.foreignBuySell !== 0) || (d.investmentTrustBuySell !== undefined && d.investmentTrustBuySell !== 0));
  }, [data]);

  const displayData = useMemo(() => {
    const startIndex = Math.max(0, data.length - barsToShow);
    const sliced = data.slice(startIndex);

    if (settings.useAdjusted) {
        return sliced.map(d => ({
            ...d,
            open: d.openAdj !== undefined ? d.openAdj : d.open,
            high: d.highAdj !== undefined ? d.highAdj : d.high,
            low: d.lowAdj !== undefined ? d.lowAdj : d.low,
            close: d.closeAdj !== undefined ? d.closeAdj : d.close,
            ma5: d.ma5Adj !== undefined ? d.ma5Adj : d.ma5,
            ma10: d.ma10Adj !== undefined ? d.ma10Adj : d.ma10,
            ma20: d.ma20Adj !== undefined ? d.ma20Adj : d.ma20,
            ma60: d.ma60Adj !== undefined ? d.ma60Adj : d.ma60,
            rsi: d.rsiAdj !== undefined ? d.rsiAdj : d.rsi,
            macd: d.macdAdj !== undefined ? d.macdAdj : d.macd,
            macdSignal: d.macdSignalAdj !== undefined ? d.macdSignalAdj : d.macdSignal,
            macdHist: d.macdHistAdj !== undefined ? d.macdHistAdj : d.macdHist
        }));
    }
    return sliced;
  }, [data, barsToShow, settings.useAdjusted]);

  const currentData = activeIndex !== null && displayData[activeIndex] ? displayData[activeIndex] : displayData[displayData.length - 1];

  if (!data || data.length === 0) return <div className="text-white">No data</div>;

  return (
    <div className="space-y-4">
      {/* Price Chart */}
      <div className="bg-slate-800 rounded-xl p-4 border border-slate-700 shadow-xl relative">
        <div className="flex justify-between items-center mb-4">
            <h3 className="text-slate-400 text-sm font-bold uppercase tracking-wider flex items-center gap-2">
                Price / Volume / MA
