// --- Helper Functions ---

// Format date based on Exchange Timezone (Moved up for dependencies)
const formatExchangeDate = (timestamp: number, timezone: string, interval: string) => {
    const date = new Date(timestamp * 1000);
    // Fix: '1mo' contains 'm' but is NOT intraday. Explicitly check for 15m/60m.
    const isIntraday = interval === '15m' || interval === '60m'; 

    try {
        const options: Intl.DateTimeFormatOptions = {
            timeZone: timezone,
            year: 'numeric',
            month: '2-digit',
            day: '2-digit',
            hour: isIntraday ? '2-digit' : undefined,
            minute: isIntraday ? '2-digit' : undefined,
            hour12: false
        };
        const formatter = new Intl.DateTimeFormat('en-US', options);
        const parts = formatter.formatToParts(date);

        const p: any = {};
        parts.forEach(({type, value}) => p[type] = value);

        if (isIntraday) {
            // Ensure 2 digits for consistency
            const h = p.hour ? p.hour.padStart(2, '0') : '00';
            const m = p.minute ? p.minute.padStart(2, '0') : '00';
            return `${p.month}-${p.day} ${h}:${m}`;
        } else {
            return `${p.year}-${p.month}-${p.day}`;
        }
    } catch (e) {
        const d = new Date(timestamp * 1000);
        const iso = d.toISOString();
        return isIntraday ? iso.slice(5, 16).replace('T', ' ') : iso.slice(0, 10);
    }
};

// Calculate the Tooltip Display Date for Weekly/Monthly candles
// Rule: Show "End of Period" date (Friday or Month End). 
// BUT if "End of Period" is in the future (i.e., Current Week/Month), show Today's date.
const getPeriodEndDisplayDate = (startDateStr: string, interval: string, timezone: string): string => {
    const parts = startDateStr.split('-').map(Number);
    // Construct UTC date for stability in math (Year, MonthIndex, Day)
    const d = new Date(Date.UTC(parts[0], parts[1] - 1, parts[2]));

    if (interval === '1wk') {
        // Add 4 days: Mon -> Fri
        d.setUTCDate(d.getUTCDate() + 4);
    } else if (interval === '1mo') {
        // Go to next month 1st, then back 1 day to get End of Month
        d.setUTCMonth(d.getUTCMonth() + 1);
        d.setUTCDate(0);
    }

    const endDateStr = d.toISOString().split('T')[0];

    // Get Today's date in target timezone to compare
    const todayStr = formatExchangeDate(Date.now() / 1000, timezone, '1d');

    // If Today < EndDate (Current Candle), return Today. Else return EndDate (Closed Candle).
    // String comparison "YYYY-MM-DD" works for ISO dates.
    return todayStr < endDateStr ? todayStr : endDateStr;
};

// Calculate the Start Date of the period (Week: Mon, Month: 1st) to enable grouping
const getPeriodStartDate = (timestamp: number, interval: string, timezone: string): string => {
    const date = new Date(timestamp * 1000);

    // Get timezone-specific Year/Month/Day/Weekday
    const parts = new Intl.DateTimeFormat('en-US', {
        timeZone: timezone,
        year: 'numeric',
        month: 'numeric',
        day: 'numeric',
        weekday: 'short',
        hour12: false
    }).formatToParts(date);

    const p: any = {};
    parts.forEach(({type, value}) => p[type] = value);

    // Construct UTC date from parts to avoid local timezone offsets messing up math
    // Note: Month is 1-based in parts, 0-based in JS Date
    let d = new Date(Date.UTC(parseInt(p.year), parseInt(p.month) - 1, parseInt(p.day)));

    if (interval === '1mo') {
        d.setUTCDate(1);
    } else if (interval === '1wk') {
        // Shift to Monday
        const day = d.getUTCDay(); // 0 (Sun) to 6 (Sat)
        // If Mon (1) -> 0 shift
        // If Tue (2) -> -1 shift
        // If Sun (0) -> -6 shift
        const diff = day === 0 ? -6 : 1 - day;
        d.setUTCDate(d.getUTCDate() + diff);
    }

    return d.toISOString().split('T')[0];
};

