// 3. Main Chart Component
// ----------------------------------------------------------------------

const StockChart: React.FC<StockChartProps> = ({ data, settings, isTaiwanStock }) => {
  const [activeIndex, setActiveIndex] = useState<number | null>(null);
  const [barsToShow, setBarsToShow] = useState(100);

  useEffect(() => {
     setBarsToShow(Math.min(100, data.length));
  }, [data.length]);

  const handleZoom = (direction: 'in' | 'out') => {
      setBarsToShow(prev => {
          const step = Math.ceil(prev * 0.2); 
          if (direction === 'in') return Math.max(20, prev - step);
          else return Math.min(data.length, prev + step); 
      });
  };

  const hasChipData = useMemo(() => {
      if (!data || data.length === 0) return false;
      return data.some(d => (d.foreignBuySell !== undefined && d.foreignBuySell !== 0) || (d.investmentTrustBuySell !== undefined && d.investmentTrustBuySell !== 0));
  }, [data]);

  const displayData = useMemo(() => {
    const startIndex = Math.max(0, data.length - barsToShow);
    const sliced = data.slice(startIndex);

    if (settings.useAdjusted) {
        return sliced.map(d => ({
            ...d,
            open: d.openAdj !== undefined ? d.openAdj : d.open,
            high: d.highAdj !== undefined ? d.highAdj : d.high,
            low: d.lowAdj !== undefined ? d.lowAdj : d.low,
            close: d.closeAdj !== undefined ? d.closeAdj : d.close,
            ma5: d.ma5Adj !== undefined ? d.ma5Adj : d.ma5,
            ma10: d.ma10Adj !== undefined ? d.ma10Adj : d.ma10,
            ma20: d.ma20Adj !== undefined ? d.ma20Adj : d.ma20,
            ma60: d.ma60Adj !== undefined ? d.ma60Adj : d.ma60,
            rsi: d.rsiAdj !== undefined ? d.rsiAdj : d.rsi,
            macd: d.macdAdj !== undefined ? d.macdAdj : d.macd,
            macdSignal: d.macdSignalAdj !== undefined ? d.macdSignalAdj : d.macdSignal,
            macdHist: d.macdHistAdj !== undefined ? d.macdHistAdj : d.macdHist
        }));
    }
    return sliced;
  }, [data, barsToShow, settings.useAdjusted]);

  const currentData = activeIndex !== null && displayData[activeIndex] ? displayData[activeIndex] : displayData[displayData.length - 1];

  if (!data || data.length === 0) return <div className="text-white">No data</div>;

  return (
    <div className="space-y-4">
      {/* Price Chart */}
      <div className="bg-slate-800 rounded-xl p-4 border border-slate-700 shadow-xl relative">
        <div className="flex justify-between items-center mb-4">
            <h3 className="text-slate-400 text-sm font-bold uppercase tracking-wider flex items-center gap-2">
                Price / Volume / MA
                {settings.useAdjusted && <span className="bg-indigo-500/20 text-indigo-300 text-[10px] px-1.5 py-0.5 rounded border border-indigo-500/30">Adj</span>}
            </h3>

            {/* Legend Overlay */}
            <div className="absolute top-4 left-1/2 -translate-x-1/2 hidden md:block z-10">
                <MALegend currentData={currentData} settings={settings} />
            </div>

            <div className="flex gap-2">
                <button onClick={() => handleZoom('out')} className="p-1.5 rounded-lg bg-slate-700 hover:bg-slate-600 text-slate-300 transition-colors"><ZoomOut size={16} /></button>
                <button onClick={() => handleZoom('in')} className="p-1.5 rounded-lg bg-slate-700 hover:bg-slate-600 text-slate-300 transition-colors"><ZoomIn size={16} /></button>
            </div>
        </div>

        <div className="h-[400px] w-full">
          <ResponsiveContainer width="100%" height="100%">
            <ComposedChart
              data={displayData}
              onMouseMove={(e: any) => {
                if (e.activeTooltipIndex !== undefined) {
                  setActiveIndex(e.activeTooltipIndex);
                }
              }}
              onMouseLeave={() => setActiveIndex(null)}
              barGap={0} // No gap between candles
            >
              <defs>
                 <linearGradient id="volGradientUp" x1="0" y1="0" x2="0" y2="1">
                    <stop offset="5%" stopColor="#f87171" stopOpacity={0.3}/>
                    <stop offset="95%" stopColor="#f87171" stopOpacity={0}/>
                 </linearGradient>
                 <linearGradient id="volGradientDown" x1="0" y1="0" x2="0" y2="1">
                    <stop offset="5%" stopColor="#34d399" stopOpacity={0.3}/>
                    <stop offset="95%" stopColor="#34d399" stopOpacity={0}/>
                 </linearGradient>
              </defs>
              <CartesianGrid strokeDasharray="3 3" stroke="#334155" vertical={false} />
              <XAxis 
                dataKey="date" 
                tick={{ fill: '#94a3b8', fontSize: 10 }} 
                tickLine={false}
                axisLine={{ stroke: '#475569' }}
                minTickGap={30}
              />
              <YAxis 
                yAxisId="price" 
                domain={['auto', 'auto']} 
                tick={{ fill: '#94a3b8', fontSize: 10 }} 
                tickLine={false}
                axisLine={false}
                width={40}
                orientation="right"
              />
              <YAxis 
                yAxisId="volume" 
                orientation="left" 
                tick={false} 
                axisLine={false} 
                width={0}
                domain={[0, (dataMax: number) => dataMax * 4]} // Compress volume to bottom 1/4
              />
              <Tooltip content={<MainTooltip isTaiwanStock={isTaiwanStock} />} cursor={{ stroke: '#64748b', strokeDasharray: '4 4' }} />

              {/* Volume Bars */}
              <Bar 
                dataKey="volume" 
                yAxisId="volume" 
                barSize={Math.max(2, 600 / barsToShow * 0.6)}
                isAnimationActive={false}
              >
                  {displayData.map((entry, index) => (
                      <Cell key={`cell-${index}`} fill={entry.close > entry.open ? "url(#volGradientUp)" : "url(#volGradientDown)"} />
                  ))}
              </Bar>

              {/* Moving Averages */}
              {settings.showMA5 && <Line type="monotone" dataKey="ma5" stroke="#fbbf24" strokeWidth={1} dot={false} yAxisId="price" isAnimationActive={false} />}
              {settings.showMA10 && <Line type="monotone" dataKey="ma10" stroke="#38bdf8" strokeWidth={1} dot={false} yAxisId="price" isAnimationActive={false} />}
              {settings.showMA20 && <Line type="monotone" dataKey="ma20" stroke="#a78bfa" strokeWidth={1} dot={false} yAxisId="price" isAnimationActive={false} />}
              {settings.showMA60 && <Line type="monotone" dataKey="ma60" stroke="#34d399" strokeWidth={1} dot={false} yAxisId="price" isAnimationActive={false} />}

              {/* Candle Stick */}
              <Bar
                dataKey="close" // Dummy key, shape handles OHLC
                shape={<CandleStickShape />}
                yAxisId="price"
                isAnimationActive={false}
                barSize={Math.max(3, 600 / barsToShow * 0.7)}
              >
                {/* Need cells to update color based on logic if not handled in shape? Shape handles it. */}
              </Bar>

            </ComposedChart>
          </ResponsiveContainer>
        </div>
      </div>

       {/* Institutional Chips Chart (Only for Taiwan Stock) */}
       {isTaiwanStock && hasChipData && (
          <div className="bg-slate-800 rounded-xl p-4 border border-slate-700 shadow-xl h-[180px]">
             <h3 className="text-slate-400 text-sm font-bold uppercase tracking-wider mb-2">Institutional Investors (Buy/Sell Net)</h3>
             <ResponsiveContainer width="100%" height="100%">
                 <BarChart data={displayData} barGap={0} syncId="stockSync">
                     <CartesianGrid strokeDasharray="3 3" stroke="#334155" vertical={false} />
                     <XAxis dataKey="date" hide />
                     <YAxis orientation="right" tick={{ fill: '#94a3b8', fontSize: 9 }} width={35} />
                     <Tooltip content={<ChipTooltip title="Foreign" />} cursor={{ fill: '#334155', opacity: 0.2 }} />
                     <ReferenceLine y={0} stroke="#475569" />
                     <Bar dataKey="foreignBuySell" name="Foreign" barSize={Math.max(2, 600 / barsToShow * 0.35)} fill="#ef4444">
                        {displayData.map((entry, index) => (
                             <Cell key={`cell-f-${index}`} fill={entry.foreignBuySell !== undefined && entry.foreignBuySell > 0 ? "#ef4444" : "#10b981"} />
                        ))}
                     </Bar>
                     {/* Add Trust as a second bar or stacked? Side by side is better for net comparison */}
                      <Bar dataKey="investmentTrustBuySell" name="Trust" barSize={Math.max(2, 600 / barsToShow * 0.35)} fill="#3b82f6">
                        {displayData.map((entry, index) => (
                             <Cell key={`cell-t-${index}`} fill={entry.investmentTrustBuySell !== undefined && entry.investmentTrustBuySell > 0 ? "#ef4444" : "#10b981"} />
                        ))}
                     </Bar>
                 </BarChart>
             </ResponsiveContainer>
          </div>
       )}

      {/* RSI Chart */}
      {settings.showRSI && (
          <div className="bg-slate-800 rounded-xl p-4 border border-slate-700 shadow-xl h-[160px]">
            <h3 className="text-slate-400 text-sm font-bold uppercase tracking-wider mb-2">RSI (14)</h3>
            <ResponsiveContainer width="100%" height="100%">
              <ComposedChart data={displayData} syncId="stockSync">
                <CartesianGrid strokeDasharray="3 3" stroke="#334155" vertical={false} />
                <XAxis dataKey="date" hide />
                <YAxis domain={[0, 100]} ticks={[30, 50, 70]} orientation="right" tick={{ fill: '#94a3b8', fontSize: 10 }} width={30} />
                <Tooltip content={<IndicatorTooltip settings={settings} />} cursor={{ stroke: '#64748b', strokeDasharray: '4 4' }} />
                <ReferenceLine y={70} stroke="#ef4444" strokeDasharray="3 3" />
                <ReferenceLine y={30} stroke="#10b981" strokeDasharray="3 3" />
                <Line type="monotone" dataKey="rsi" stroke="#38bdf8" strokeWidth={2} dot={false} isAnimationActive={false} />
              </ComposedChart>
            </ResponsiveContainer>
          </div>
      )}

      {/* MACD Chart */}
      <div className="bg-slate-800 rounded-xl p-4 border border-slate-700 shadow-xl h-[180px]">
        <h3 className="text-slate-400 text-sm font-bold uppercase tracking-wider mb-2">MACD</h3>
        <ResponsiveContainer width="100%" height="100%">
          <ComposedChart data={displayData} syncId="stockSync">
            <CartesianGrid strokeDasharray="3 3" stroke="#334155" vertical={false} />
            <XAxis dataKey="date" hide />
            <YAxis orientation="right" tick={{ fill: '#94a3b8', fontSize: 10 }} width={30} />
            <Tooltip content={<MACDTooltip />} cursor={{ stroke: '#64748b', strokeDasharray: '4 4' }} />
            <Bar dataKey="macdHist" barSize={Math.max(2, 600 / barsToShow * 0.6)} isAnimationActive={false}>
              {displayData.map((entry, index) => (
                <Cell key={`cell-${index}`} fill={(entry.macdHist || 0) >= 0 ? "#ef4444" : "#10b981"} />
              ))}
            </Bar>
            <Line type="monotone" dataKey="macd" stroke="#fb923c" strokeWidth={1} dot={false} isAnimationActive={false} />
            <Line type="monotone" dataKey="macdSignal" stroke="#22d3ee" strokeWidth={1} dot={false} isAnimationActive={false} />
          </ComposedChart>
        </ResponsiveContainer>
      </div>

       {/* KDJ Chart */}
       {(settings.showK || settings.showD || settings.showJ) && (
          <div className="bg-slate-800 rounded-xl p-4 border border-slate-700 shadow-xl h-[160px]">
            <h3 className="text-slate-400 text-sm font-bold uppercase tracking-wider mb-2">KDJ</h3>
            <ResponsiveContainer width="100%" height="100%">
              <ComposedChart data={displayData} syncId="stockSync">
                <CartesianGrid strokeDasharray="3 3" stroke="#334155" vertical={false} />
                <XAxis dataKey="date" hide />
                <YAxis domain={[0, 100]} orientation="right" tick={{ fill: '#94a3b8', fontSize: 10 }} width={30} />
                <Tooltip content={<IndicatorTooltip settings={settings} />} cursor={{ stroke: '#64748b', strokeDasharray: '4 4' }} />
                {settings.showK && <Line type="monotone" dataKey="k" stroke="#facc15" strokeWidth={1.5} dot={false} isAnimationActive={false} />}
                {settings.showD && <Line type="monotone" dataKey="d" stroke="#f472b6" strokeWidth={1.5} dot={false} isAnimationActive={false} />}
                {settings.showJ && <Line type="monotone" dataKey="j" stroke="#c084fc" strokeWidth={1.5} dot={false} isAnimationActive={false} />}
              </ComposedChart>
            </ResponsiveContainer>
          </div>
       )}
    </div>
  );
};

