// --- Helper: Estimate Volume Trend ---
interface VolumeProjection {
    currentVolume: number;
    projectedVolume: number;
    yesterdayVolume: number;
    changePercent: number;
    trend: 'Aggressive' | 'Moderate' | 'Flat' | 'Contraction' | 'Insufficient' | 'Closed';
    trendLabel: string;
    progressRate: number;
}

const estimateVolumeTrend = (data: StockDataPoint[], isTaiwanStock: boolean, interval: TimeInterval): VolumeProjection | null => {
    // Only calculate for Daily interval and sufficient data
    if (interval !== '1d' || data.length < 2 || !isTaiwanStock) return null;

    const latest = data[data.length - 1];
    const prev = data[data.length - 2];

    // Check if latest data is "Today"
    const now = new Date();
    // Taiwan Time conversion
    const twTime = new Date(now.toLocaleString("en-US", {timeZone: "Asia/Taipei"}));
    const todayStr = twTime.toISOString().split('T')[0];

    // If data date is not today, market is closed for that day or data is old
    if (latest.date !== todayStr) return null;

    const currentHour = twTime.getHours();
    const currentMinute = twTime.getMinutes();

    // Taiwan Market Hours: 09:00 - 13:30 (270 mins)
    const startHour = 9;
    const endHour = 13;
    const endMinute = 30;

    const minutesElapsed = (currentHour - startHour) * 60 + currentMinute;
    const totalMinutes = 270;

    // Check Market Status
    if (minutesElapsed < 0) return null; // Pre-market

    // If Market Closed (> 13:30), just compare final volumes
    if (minutesElapsed >= totalMinutes) {
         const changePercent = ((latest.volume - prev.volume) / prev.volume) * 100;
         let trend: VolumeProjection['trend'] = 'Flat';
         let trendLabel = '量平';

         if (changePercent > 20) { trend = 'Aggressive'; trendLabel = '爆量'; }
         else if (changePercent > 5) { trend = 'Moderate'; trendLabel = '溫和放量'; }
         else if (changePercent < -5) { trend = 'Contraction'; trendLabel = '量縮'; }

         return {
            currentVolume: latest.volume,
            projectedVolume: latest.volume,
            yesterdayVolume: prev.volume,
            changePercent,
            trend,
            trendLabel,
            progressRate: 1
         };
    }

    const progressRate = minutesElapsed / totalMinutes;

    // Constraint: Data insufficient
    if (progressRate < 0.1) {
        return {
            currentVolume: latest.volume,
            projectedVolume: 0,
            yesterdayVolume: prev.volume,
            changePercent: 0,
            trend: 'Insufficient',
            trendLabel: '資料不足',
            progressRate
        };
    }

    // Estimate
    const projectedVolume = latest.volume / progressRate;
    const changePercent = ((projectedVolume - prev.volume) / prev.volume) * 100;

    let trend: VolumeProjection['trend'] = 'Flat';
    let trendLabel = '量平';

    if (changePercent > 20) { trend = 'Aggressive'; trendLabel = '預估爆量'; }
    else if (changePercent > 5) { trend = 'Moderate'; trendLabel = '預估放量'; }
    else if (changePercent < -5) { trend = 'Contraction'; trendLabel = '預估量縮'; }

    return {
        currentVolume: latest.volume,
        projectedVolume: projectedVolume,
        yesterdayVolume: prev.volume,
        changePercent,
        trend,
        trendLabel,
        progressRate
    };
};

