    shortCommentary: string; // One sentence summary
    progressRate: number;
    status: 'Active' | 'Insufficient' | 'Closed';
}

const estimateVolumeTrend = (data: StockDataPoint[], isTaiwanStock: boolean, interval: TimeInterval): VolumeProjection | null => {
    // Only calculate for Daily interval and sufficient data
    if (interval !== '1d' || data.length < 2 || !isTaiwanStock) return null;

    const latest = data[data.length - 1];
    const prev = data[data.length - 2];

    // Check if latest data is "Today"
    const now = new Date();
    // Taiwan Time conversion
    const twTime = new Date(now.toLocaleString("en-US", {timeZone: "Asia/Taipei"}));
    const todayStr = twTime.toISOString().split('T')[0];

    // If data date is not today, market is closed for that day or data is old
    if (latest.date !== todayStr) return null;

    const currentHour = twTime.getHours();
    const currentMinute = twTime.getMinutes();

    // Taiwan Market Hours: 09:00 - 13:30 (270 mins)
    const startHour = 9;
    const totalMinutesInDay = 270;

    // Calculate Minutes Elapsed
    // 9:00 is minute 0. 13:30 is minute 270.
    let minutesElapsed = (currentHour - startHour) * 60 + currentMinute;

    // Clamp time boundaries
    if (minutesElapsed < 0) return null; // Pre-market

    // If Market Closed (> 13:30), treat as full day
    const isClosed = minutesElapsed >= totalMinutesInDay;
    if (isClosed) minutesElapsed = totalMinutesInDay;

    // 1. Calculate Time Progress
    const progressRate = minutesElapsed / totalMinutesInDay;

    // Constraint: Data insufficient for projection
    if (!isClosed && progressRate < 0.1) {
        return {
            currentVolume: latest.volume,
            projectedVolume: 0,
            yesterdayVolume: prev.volume,
            changePercent: 0,
            trendDefinition: 'Data insufficient',
            trendColor: 'text-slate-400',
            shortCommentary: '開盤時間過短，數據不足以進行全日預估。',
            progressRate,
            status: 'Insufficient'
        };
    }

    // 2. Estimate End-of-Day Volume
    // If closed, projected is actual. If intraday, project linear.
    // Note: Volume U-shape distribution is real, but we follow the linear requirement for this specific task.
    const projectedVolume = isClosed ? latest.volume : Math.round(latest.volume / progressRate);

    // 3. Calculate Volume Change %
    const changePercent = ((projectedVolume - prev.volume) / prev.volume) * 100;

    // 4. Determine Volume Trend & Commentary
    let trendDefinition = "";
    let shortCommentary = "";
    let trendColor = "";

    if (changePercent > 20) {
        trendDefinition = "Aggressive Volume Increase (爆量)";
        shortCommentary = "市場交投極度熱絡，買盤湧入，留意股價波動風險。";
        trendColor = "text-red-400";
    } else if (changePercent >= 5) { // 5% to 20%
        trendDefinition = "Moderate Increase (溫和放量)";
        shortCommentary = "量能溫和放大，人氣逐漸匯聚，有利於趨勢發展。";
        trendColor = "text-rose-300";
    } else if (changePercent >= -5) { // -5% to +5%
        trendDefinition = "Flat Volume (量平)";
        shortCommentary = "預估成交量與昨日持平，多空力道均衡，市場觀望。";
        trendColor = "text-slate-300";
    } else { // < -5%
        trendDefinition = "Volume Contraction (量縮)";
        shortCommentary = "預估量能明顯萎縮，人氣退潮，短期可能陷入整理。";
        trendColor = "text-emerald-400";
    }

    return {
        currentVolume: latest.volume,
        projectedVolume,
        yesterdayVolume: prev.volume,
        changePercent,
        trendDefinition,
        trendColor,
        shortCommentary,
        progressRate,
        status: isClosed ? 'Closed' : 'Active'
    };
};

