// --- Helper: Estimate Volume Trend (U-Shape Weighted) ---
interface VolumeProjection {
    currentVolume: number;
    projectedVolume: number;
    yesterdayVolume: number;
    changePercent: number;
    status: 'Active' | 'Insufficient' | 'Closed';
}

const estimateVolumeTrend = (data: StockDataPoint[], isTaiwanStock: boolean, interval: TimeInterval): VolumeProjection | null => {
    // Only calculate for Daily interval and sufficient data for Taiwan Stocks
    if (interval !== '1d' || data.length < 2 || !isTaiwanStock) return null;

    const latest = data[data.length - 1];
    const prev = data[data.length - 2];

    // Time logic for Taiwan (Asia/Taipei)
    const now = new Date();
    const twTime = new Date(now.toLocaleString("en-US", {timeZone: "Asia/Taipei"}));
    const todayStr = twTime.toISOString().split('T')[0];

    // Check if latest data is actually from today
    if (latest.date !== todayStr) return null;

    const currentHour = twTime.getHours();
    const currentMinute = twTime.getMinutes();

    // Taiwan Market Hours: 09:00 - 13:30 (270 mins)
    const startHour = 9;
    const totalMinutesInDay = 270;
    let minutesElapsed = (currentHour - startHour) * 60 + currentMinute;

    if (minutesElapsed < 0) return null; // Market not open yet

    const isClosed = minutesElapsed >= totalMinutesInDay;
    if (isClosed) minutesElapsed = totalMinutesInDay;

    /**
     * U-Shape Weighting Logic (Taiwan Stock Market Heuristics):
     * 1. 09:00 - 09:30 (First 30m): High intensity. Approx 22% of daily volume.
     * 2. 09:30 - 13:00 (Mid-day): Lower intensity. Approx 58% of daily volume.
     * 3. 13:00 - 13:30 (Closing rush + Auction): High intensity. Approx 20% of daily volume.
     */
    const getVolumeWeight = (mins: number): number => {
        if (mins <= 30) {
            // Linear progress within the first 22% of volume
            return (mins / 30) * 0.22;
        } else if (mins <= 240) {
            // Mid-day progress: from 22% to 80% (58% total weight for 210 mins)
            return 0.22 + ((mins - 30) / 210) * 0.58;
        } else if (mins < 270) {
            // Closing rush: from 80% up to ~93% before the final auction
            return 0.80 + ((mins - 240) / 30) * 0.13;
        } else {
            // Full day including final auction (100%)
            return 1.0;
        }
    };

    const weight = getVolumeWeight(minutesElapsed);

    // Filter out very early data to avoid extreme volatility in projection
    if (!isClosed && minutesElapsed < 10) {
        return {
            currentVolume: latest.volume,
            projectedVolume: 0,
            yesterdayVolume: prev.volume,
            changePercent: 0,
            status: 'Insufficient'
        };
    }

    const projectedVolume = isClosed ? latest.volume : Math.round(latest.volume / weight);
    const changePercent = prev.volume > 0 ? ((projectedVolume - prev.volume) / prev.volume) * 100 : 0;

    return {
        currentVolume: latest.volume,
        projectedVolume,
        yesterdayVolume: prev.volume,
        changePercent,
        status: isClosed ? 'Closed' : 'Active'
    };
};

